// Keep a click-opened popover inside the viewport: measure the trigger on open
// and, when there isn't room below for the menu, flip it above the trigger.
// Attach the returned ref to the menu's relative anchor and use `up` to swap the
// menu's position classes (`bottom-full mb-1` when up, `top-full mt-1` when down).
// estHeight is a rough menu height; being generous just flips a little earlier.
function useDropUp(open, estHeight = 300) {
  const anchorRef = useRef(null);
  const [up, setUp] = useState(false);
  useLayoutEffect(() => {
    if (!open || !anchorRef.current || typeof window === "undefined") return;
    const r = anchorRef.current.getBoundingClientRect();
    const below = window.innerHeight - r.bottom;
    // Flip up only when below is tight AND there's genuinely more room above.
    setUp(below < estHeight && r.top > below);
  }, [open, estHeight]);
  return [anchorRef, up];
}

// Turn a stored profile_role ('owner' | 'admin' | 'recruiter' | 'interviewer')
// into the friendly label the workspace greeting/sidebar expect.
const ROLE_LABELS = { owner: "Tenant", admin: "Hiring Manager", recruiter: "Recruiter", interviewer: "Interviewer" };

// Load the signed-in customer's profile + company into the shape the app's
// root state uses. Returns null when the user has no company profile (e.g. an
// Aster admin, or a not-yet-provisioned signup) so callers can fall back or
// bounce them out. RLS guarantees they can only read their own company's rows.
// Tiers were renamed to launch/scale/elite in migration 0040. A database that
// has not had it applied yet still answers with the old vocabulary, and an
// unrecognised tier would fall through to the most restrictive plan. Safe to
// delete once 0040 is applied everywhere.

async function loadCustomerSession(userId, fallbackEmail) {
  if (!hasSupabase) return null;
  const { data, error } = await supabase
    .from("profiles")
    .select("company_id, full_name, role, phone, avatar_path, notify_prefs, calendar_provider, activities_seen_at, onboarding, companies ( name, slug, plan, logo_url, address, address_street, address_city, address_state, address_postcode, address_country, registration_no, subscriptions ( status, cycle, current_period_end ) )")
    .eq("id", userId)
    .maybeSingle();
  if (error || !data) return null;
  // Parse the name from full_name ONLY — never fall back to the email. Some invited
  // accounts were provisioned with their email as full_name; treat a bare email as
  // "no name set" so First/Last render empty (with placeholders) instead of the
  // address. Saving a real name self-heals the row via update_my_profile.
  const rawName = (data.full_name || "").trim();
  const looksLikeEmail = /\S+@\S+\.\S+/.test(rawName) && !/\s/.test(rawName);
  const parts = (looksLikeEmail ? "" : rawName).split(/\s+/).filter(Boolean);
  const co = data.companies || {};
  // subscriptions.company_id is unique, so PostgREST embeds a single row - but
  // tolerate the array shape too.
  const sub = (Array.isArray(co.subscriptions) ? co.subscriptions[0] : co.subscriptions) || {};
  // Prefer the discrete address columns; fall back to a best-effort parse of the
  // legacy freeform `address` for rows saved before the structured migration.
  const structured = { street: co.address_street || "", city: co.address_city || "", state: co.address_state || "", postcode: co.address_postcode || "", country: co.address_country || "" };
  const addressParts = Object.values(structured).some(Boolean) ? structured : parseAddress(co.address || "");
  // Whether this account uses email-code 2FA. Read on its own so a missing column
  // (before migration 0084) cannot error the main session query and lock people out.
  let email2fa = false;
  try {
    const { data: f, error: fe } = await supabase.from("profiles").select("email_2fa_enabled").eq("id", userId).maybeSingle();
    email2fa = !fe && !!f?.email_2fa_enabled;
  } catch { /* column absent pre-migration: treat as off */ }
  const sessionResult = {
    userId,
    companyId: data.company_id,
    profile: {
      id: userId, // the auth user id, so self-checks (e.g. "don't assign myself") work
      firstName: parts[0] || "",
      lastName: parts.slice(1).join(" "),
      email: fallbackEmail || "",
      role: ROLE_LABELS[data.role] || "Hiring Manager",
      phone: data.phone || "",
      notifications: data.notify_prefs || {},
      // Per-user onboarding/tour flags, so a "skip" persists across browsers.
      onboarding: data.onboarding || {},
      // Read separately and defensively: a missing column (migration not yet
      // applied) returns an error we ignore rather than breaking the whole session
      // load and locking everyone out.
      email2fa,
    },
    avatarPath: data.avatar_path || null,
    calendarProvider: data.calendar_provider || null,
    company: co.name || "Your workspace",
    companySlug: co.slug || null, // the <slug>.hireaster.com subdomain for this workspace
    // plan_tier enum and app plan key are the same vocabulary since 0040:
    // launch | scale | elite | enterprise.
    plan: PLAN_TIER_ALIASES[co.plan] || co.plan || "launch",
    // Billing state, so a reload doesn't lose the trial countdown or show a
    // placeholder renewal date.
    activitiesSeenAt: data.activities_seen_at || null,
    subStatus: sub.status || null,
    planCycle: sub.cycle === "yearly" ? "yearly" : "monthly",
    renewsAt: sub.current_period_end || null,
    trialDaysLeft: sub.status === "trialing" ? daysUntil(sub.current_period_end) : 0,
    logoUrl: co.logo_url || null,
    address: co.address || "",
    addressParts,
    registrationNo: co.registration_no || "",
  };
  return sessionResult;
}

// Onboarding/tour flags persist per USER on profiles.onboarding (server), and are
// mirrored to localStorage for an instant read. A flag counts as "done" if either
// source says so; ending/skipping a tour writes BOTH, so a "skip" sticks to the
// account across browsers and incognito windows, not just the one that clicked it.
function onboardingDone(profile, serverKey, lsKey) {
  if (profile && profile.onboarding && profile.onboarding[serverKey] === true) return true;
  try { return localStorage.getItem(lsKey) === "done"; } catch { return false; }
}
function markOnboardingDone(serverKey, lsKey) {
  try { if (lsKey) localStorage.setItem(lsKey, "done"); } catch { /* private mode */ }
  if (hasSupabase) { try { supabase.rpc("mark_onboarding", { p_key: serverKey }).catch(() => {}); } catch { /* ignore */ } }
}

// Buy a plan, or switch to a different one.
//
// First purchase: create-checkout-session mints a Stripe Checkout session and we
// redirect; stripe-webhook activates the plan once payment lands.
//
// Already subscribed: there is nothing to check out. The function switches the
// price on the live subscription and Stripe prorates it (an upgrade is invoiced
// immediately, a downgrade credits the unused time against the next invoice), so
// no redirect happens. Sending an existing subscriber back through Checkout would
// open a SECOND subscription and bill them for both plans.
//
// Resolves to an error string; on a redirect it never returns.
async function stripeCheckout(planKey, cycle) {
  try {
    const { data, error } = await supabase.functions.invoke("create-checkout-session", {
      body: { plan: planKey, cycle, return_url: window.location.origin },
    });
    if (error) {
      // Supabase wraps a non-2xx in a FunctionsHttpError; the real reason (e.g.
      // a Stripe "No such price") is only in the response body.
      let reason = "";
      try { const body = await error.context?.json?.(); reason = body?.detail || body?.error || ""; } catch { /* non-JSON body */ }
      return reason ? `Checkout error: ${reason}` : "Couldn't start checkout. Try again.";
    }
    // The upgrade charge needs 3-D Secure. It was attempted off-session against the
    // saved card, so there was nobody there to authenticate and Stripe left the
    // invoice open. Stripe's hosted invoice page can run the challenge, so send them
    // there to finish paying rather than dropping them on a past-due billing screen
    // with no way out. 3DS is effectively mandatory in Malaysia and the EU.
    if (data?.requires_action && data?.url) {
      window.location.assign(data.url);
      return null;
    }
    // Plan switched on the existing subscription: no checkout to send them to.
    // Reload so the new plan, limits and billing state come back from the server.
    if (data?.changed || data?.unchanged) {
      window.location.assign("/billing?plan=changed");
      return null;
    }
    if (!data?.url) return `Checkout error: ${data?.detail || data?.error || "no URL returned"}`;
    window.location.href = data.url;
    return null;
  } catch (e) {
    console.error("checkout", e);
    return "Couldn't open checkout. Try again.";
  }
}

// Redirect to Stripe's hosted Billing Portal: real invoices and their PDFs, the
// saved card, and cancellation. Resolves to an error string, or never returns.
async function stripePortal() {
  try {
    const { data, error } = await supabase.functions.invoke("create-portal-session", {
      body: { return_url: window.location.origin },
    });
    if (error) {
      let reason = "";
      try { const body = await error.context?.json?.(); reason = body?.detail || body?.error || ""; } catch { /* non-JSON body */ }
      return reason || "Couldn't open the billing portal. Try again.";
    }
    if (!data?.url) return data?.detail || data?.error || "Couldn't open the billing portal.";
    window.location.href = data.url;
    return null;
  } catch (e) {
    console.error("portal", e);
    return "Couldn't open the billing portal. Try again.";
  }
}

// Stripe reports amounts in the currency's minor unit (sen, cents). Zero-decimal
// currencies (JPY, KRW…) don't, so don't divide those.
// https://docs.stripe.com/currencies#zero-decimal
const ZERO_DECIMAL = new Set(["bif", "clp", "djf", "gnf", "jpy", "kmf", "krw", "mga", "pyg", "rwf", "ugx", "vnd", "vuv", "xaf", "xof", "xpf"]);

// { amount: 52900, currency: "myr" } → "RM 529.00"
function formatMoney(amount, currency, opts = {}) {
  if (typeof amount !== "number" || !currency) return "";
  const zero = ZERO_DECIMAL.has(currency.toLowerCase());
  const value = zero ? amount : amount / 100;
  try {
    return new Intl.NumberFormat(undefined, {
      style: "currency",
      currency: currency.toUpperCase(),
      minimumFractionDigits: opts.whole ? 0 : (zero ? 0 : 2),
      maximumFractionDigits: zero ? 0 : 2,
    }).format(value);
  } catch {
    return `${currency.toUpperCase()} ${value.toFixed(zero ? 0 : 2)}`;
  }
}

// Live Stripe amounts keyed "<plan>|<cycle>", fetched once per page load and
// shared by every screen that quotes a price. A single source of truth: the app
// can never advertise an amount different from the one the card is charged.
let planPricesPromise = null;
function fetchPlanPrices() {
  if (!hasSupabase) return Promise.resolve({});
  if (!planPricesPromise) {
    planPricesPromise = supabase.functions
      .invoke("get-plan-prices")
      .then(({ data, error }) => {
        if (error || !data?.prices) { console.error("get-plan-prices failed:", error); return {}; }
        return data.prices;
      })
      .catch((e) => { console.error("get-plan-prices failed:", e); return {}; });
  }
  return planPricesPromise;
}

// null while loading, {} when unavailable, otherwise the price map.
function usePlanPrices() {
  const [prices, setPrices] = useState(null);
  useEffect(() => {
    let cancelled = false;
    fetchPlanPrices().then((p) => { if (!cancelled) setPrices(p); });
    return () => { cancelled = true; };
  }, []);
  return prices;
}

// Whole days from today to a `date` column ('YYYY-MM-DD'), floored at 0. Parsed
// as local midnight so a same-day expiry reads as 0, not -1 from a UTC shift.
function daysUntil(dateStr) {
  if (!dateStr) return 0;
  const end = new Date(`${dateStr}T00:00:00`).getTime();
  if (Number.isNaN(end)) return 0;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return Math.max(0, Math.round((end - today.getTime()) / 86400000));
}

// created_at → the relative string the UI's recency parser understands
// ("today" | "Nd ago"). Anything under a day reads as "today".
function relDaysAgo(iso) {
  if (!iso) return "today";
  const days = Math.floor((Date.now() - new Date(iso).getTime()) / 86400000);
  return days <= 0 ? "today" : `${days}d ago`;
}

// "just now" | "12m ago" | "3h ago" | "5d ago". Used by the activity feed, which
// used to carry hardcoded strings like "1h ago" whatever the row's real age.
function relTime(iso) {
  if (!iso) return "";
  const secs = Math.max(0, Math.floor((Date.now() - new Date(iso).getTime()) / 1000));
  if (secs < 60) return "just now";
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

// Turn scorecard ratings into the hire recommendation the profile expects.
function recommendationFromRatings(ratings) {
  const vals = Object.values(ratings || {}).filter((n) => typeof n === "number");
  if (!vals.length) return "yes";
  const avg = vals.reduce((s, n) => s + n, 0) / vals.length;
  return avg >= 3.6 ? "strong_yes" : avg >= 2.8 ? "yes" : avg >= 2 ? "no" : "strong_no";
}

// Swap the reassignable demo datasets for real ones. Every screen reads these
// module bindings directly, so a root re-render after this call shows real data.
function applyWorkspaceData({ jobs, candidates, applicantsByJob, matchesByJob }) {
  MOCK_JOBS = jobs;
  MOCK_CANDIDATES = candidates;
  APPLICANTS_BY_JOB = applicantsByJob;
  MOCK_MATCHES = matchesByJob;
}

// Fetch the signed-in company's jobs, candidates, applications, interviews and
// scorecards and map them into the shapes the app already renders. Returns null
// on failure or when there's nothing to show (so callers keep the demo data).
async function loadWorkspaceData(companyId) {
  if (!hasSupabase || !companyId) return null;
  const [jobsRes, candRes, appRes, ivRes, scRes, viewsRes, srRes, iqRes, offRes] = await Promise.all([
    supabase.from("jobs").select("id, title, status, details, created_at, expires_at").eq("company_id", companyId),
    supabase.from("candidates").select("id, parsed, full_name, email, file_name, status, has_photo, photo_path, resume_path, created_at").eq("company_id", companyId),
    supabase.from("applications").select("id, candidate_id, job_id, stage, match_score, match_reasons, source, created_at").eq("company_id", companyId),
    supabase.from("interviews").select("candidate_id, job_id, interviewer_id, interviewer_name, scheduled_at, status, provider, attendees, meeting_link").eq("company_id", companyId),
    supabase.from("scorecards").select("id, candidate_id, interviewer_id, ratings, notes, created_at").eq("company_id", companyId),
    supabase.rpc("get_job_view_stats"), // per-job apply-page view analytics
    supabase.from("schedule_requests").select("application_id, requested_by").eq("company_id", companyId).is("resolved_at", null),
    supabase.from("interview_questions").select("candidate_id, job_id, questions").eq("company_id", companyId),
    supabase.from("offers").select("candidate_id, status").eq("company_id", companyId),
  ]);
  const jobRows = jobsRes.data || [];
  // A hard error → keep whatever's loaded. A workspace with zero jobs is still a
  // real (empty) workspace: load its candidates so imports show even before any
  // job is posted.
  if (jobsRes.error) return null;

  // Apply-page view stats keyed by job id: { total, uniques, sources:{src:count} }.
  const viewsByJob = {};
  (viewsRes?.data || []).forEach((r) => { viewsByJob[r.job_id] = { total: Number(r.total) || 0, uniques: Number(r.uniques) || 0, sources: r.sources || {} }; });

  const jobs = jobRows.map((j) => ({ id: j.id, title: j.title, status: j.status, ...(j.details || {}), posted_at: j.created_at, expires_at: j.expires_at || null, viewStats: viewsByJob[j.id] || { total: 0, uniques: 0, sources: {} } }));
  const jobTitle = Object.fromEntries(jobs.map((j) => [j.id, j.title]));

  // Resume PDFs and profile photos live in the private resumes bucket; mint
  // short-lived signed URLs so the app can show them without making them public.
  const filePaths = [...new Set((candRes.data || []).flatMap((c) => [c.photo_path, c.resume_path]).filter(Boolean))];
  const urlByPath = {};
  if (filePaths.length) {
    const { data: signed } = await supabase.storage.from("resumes").createSignedUrls(filePaths, 3600);
    (signed || []).forEach((s) => { if (s.path && s.signedUrl) urlByPath[s.path] = s.signedUrl; });
  }

  const candidates = (candRes.data || []).map((c) => ({
    id: c.id,
    fileName: c.file_name || "resume.pdf",
    // An unparsed applicant has no `parsed` blob, so the name and email they typed
    // into the apply form are the only thing we can show them by.
    fullName: c.full_name || null,
    email: c.email || null,
    status: c.status || "parsed",
    hasPhoto: !!c.has_photo,
    avatarUrl: c.photo_path ? (urlByPath[c.photo_path] || null) : null,
    resumeUrl: c.resume_path ? (urlByPath[c.resume_path] || null) : null,
    createdAt: c.created_at || null,   // for real period-over-period growth
    parsed: c.parsed || null,
  }));

  // Company team members double as the interviewer pool (no separate
  // interviewers table): used for booking, scorecard attribution and the
  // Interviewers screen.
  // Removed teammates keep their row (it anchors their scorecards and interviews)
  // but must not appear in the team list.
  const profRes = await supabase.from("profiles").select("id, full_name, email, role, status").eq("company_id", companyId).neq("status", "suspended");
  const profName = Object.fromEntries((profRes.data || []).map((p) => [p.id, p.full_name || "Interviewer"]));
  const interviewers = (profRes.data || []).map((p) => ({ id: p.id, name: p.full_name || "Interviewer", email: p.email || "", role: p.role, pending: p.status === "invited", timezone: "Asia/Kuala_Lumpur" }));

  // Pending teammate invitations (no profile yet). They still consume a seat on
  // the server, so the team-seats meter must count them to match enforcement.
  const invRes = await supabase.from("invitations").select("id, email, role").eq("company_id", companyId).is("accepted_at", null).gt("expires_at", new Date().toISOString());
  const pendingInvites = (invRes.data || []).map((v) => ({ id: v.id, email: v.email || "", role: v.role || "interviewer" }));

  // Job interviewer pools: which teammates can see each job's applicants.
  const jaRes = await supabase.from("job_assignments").select("job_id, profile_id").eq("company_id", companyId);
  const jobAssignments = (jaRes.data || []).map((a) => ({ job_id: a.job_id, profile_id: a.profile_id }));

  const applicantsByJob = {};
  const matchesByJob = {};
  for (const a of appRes.data || []) {
    (applicantsByJob[a.job_id] ||= []).push({
      candidateId: a.candidate_id,
      applicationId: a.id,
      appliedAt: relDaysAgo(a.created_at),
      appliedAtIso: a.created_at,
      // For non-matches, match_reasons holds the AI's fit explanation (why the
      // candidate was set aside). Carried here so the Non-Matches card can show
      // it — free, since it was generated during the parse. Only rendered on
      // cards where fit === "other" (for ranked strong matches this same column
      // holds the AI Rank rationale instead, which we never show here).
      fitReason: a.match_reasons || "",
      baseStage: a.stage,
      rejectionEmailSent: false,
      source: a.source || "Career Page",
    });
    if (a.match_score != null) {
      (matchesByJob[a.job_id] ||= []).push({
        candidateId: a.candidate_id,
        score: a.match_score > 1 ? a.match_score / 100 : a.match_score,
        rationale: a.match_reasons || "",
      });
    }
  }

  // Best-effort Strong / Other classification (migration 0067). Loaded separately
  // so a missing `fit` column (before the migration lands) can't break the whole
  // applicants load — rows just stay unclassified (rendered as Strong).
  try {
    const { data: fitRows } = await supabase.from("applications").select("candidate_id, job_id, fit").eq("company_id", companyId);
    if (Array.isArray(fitRows)) {
      const fitBy = new Map(fitRows.map((f) => [`${f.job_id}:${f.candidate_id}`, f.fit]));
      for (const [jobId, list] of Object.entries(applicantsByJob)) {
        for (const row of list) { const v = fitBy.get(`${jobId}:${row.candidateId}`); if (v) row.fit = v; }
      }
    }
  } catch { /* column missing / offline: leave unclassified */ }

  // Candidate display name by id, so a booking carries the name at load time and
  // doesn't depend on a live candidates-array lookup when it's rendered.
  const candNameById = Object.fromEntries(candidates.map((c) => [c.id, c.parsed?.name || null]));

  const bookings = {};
  for (const iv of ivRes.data || []) {
    if (iv.status !== "scheduled" || !iv.scheduled_at) continue;
    const start = new Date(iv.scheduled_at);
    bookings[iv.candidate_id] = {
      status: "scheduled",
      jobId: iv.job_id,
      confirmedSlot: { start: start.toISOString(), end: new Date(start.getTime() + 30 * 60000).toISOString() },
      provider: iv.provider || "google",
      attendees: Array.isArray(iv.attendees) ? iv.attendees : [],
      meetingLink: iv.meeting_link || null,
      request: { candidateId: iv.candidate_id, candidateName: candNameById[iv.candidate_id] || null, jobTitle: jobTitle[iv.job_id] || "Interview", interviewerName: iv.interviewer_name || profName[iv.interviewer_id] || "Interviewer" },
    };
  }

  const scorecards = {};
  for (const s of scRes.data || []) {
    (scorecards[s.candidate_id] ||= []).push({
      id: s.id,
      interviewerId: s.interviewer_id,
      interviewer: profName[s.interviewer_id] || "Interviewer",
      ratings: s.ratings || {},
      recommendation: recommendationFromRatings(s.ratings),
      notes: s.notes || "",
      submittedAt: relDaysAgo(s.created_at),
    });
  }

  // Open interview requests (interviewer flagged a candidate for HR to schedule).
  const scheduleRequests = (srRes.data || []).map((r) => ({ application_id: r.application_id, requested_by: r.requested_by }));

  // Generated AI interview questions, keyed by "candidateId:jobId".
  const interviewQuestions = {};
  for (const q of iqRes.data || []) interviewQuestions[`${q.candidate_id}:${q.job_id}`] = Array.isArray(q.questions) ? q.questions : [];

  // Offers, keyed by candidate: their current status (sent | accepted | declined).
  const offers = {};
  for (const o of offRes.data || []) offers[o.candidate_id] = { status: o.status };

  return { jobs, candidates, applicantsByJob, matchesByJob, bookings, scorecards, interviewers, pendingInvites, jobAssignments, scheduleRequests, interviewQuestions, offers };
}

// ---------- Mock data (stands in for Supabase + Claude + Voyage in this preview) ----------

// Reassignable so a signed-in workspace can swap this demo set for real
// Supabase rows (see applyWorkspaceData). Left as the seed data in mock mode.
let MOCK_CANDIDATES = [];

// Reassignable (see applyWorkspaceData): held in `jobs` state, but also read as
// a module binding by buildActivities, so it's swapped to real data on hydrate.
let MOCK_JOBS = [];

let MOCK_MATCHES = {};

// Interviewer pool. Hydrated from the company's Supabase profiles in
// loadWorkspaceData (there is no separate interviewers table, the team members
// are the interviewers). Empty until real data loads; interviewers added in the
// Interviewers screen are client-side for the session.
const INITIAL_INTERVIEWERS = [];

// Collaborative scorecards: structured interview feedback, one per interviewer.
const SCORE_CRITERIA = [
  { key: "technical", label: "Technical skills" },
  { key: "communication", label: "Communication" },
  { key: "cultureFit", label: "Culture fit" },
  { key: "experience", label: "Experience" },
];
const RECOMMENDATIONS = [
  { key: "strong_yes", label: "Strong yes", color: "#166534", bg: "#DCFCE7" },
  { key: "yes", label: "Yes", color: "#15803D", bg: "#F0FDF4" },
  { key: "no", label: "No", color: "#B91C1C", bg: "#FEF2F2" },
  { key: "strong_no", label: "Strong no", color: "#991B1B", bg: "#FEE2E2" },
];
// Real scorecards load via setScorecards from Supabase; empty by default (no mock).
const SCORECARDS_BY_CANDIDATE = {};

// Applicants keyed by job id, the single source of truth for both the
// Jobs card count and the Applicants screen. Base stages here; a shared
// override (e.g. from a confirmed booking) can win at render time.
let APPLICANTS_BY_JOB = {};

const applicantCountFor = (jobId) => (APPLICANTS_BY_JOB[jobId] || []).length;

// The candidate's real pipeline stage from loaded data (preferring a given job),
// so a view that wasn't handed a stage (e.g. an interviewer opening a profile
// from "Your Interviews") shows the true stage instead of defaulting to
// "applied". Returns null when the candidate isn't in any loaded job list.
const stageForCandidate = (candidateId, jobId = null) => {
  if (jobId && Array.isArray(APPLICANTS_BY_JOB[jobId])) {
    const a = APPLICANTS_BY_JOB[jobId].find((x) => x.candidateId === candidateId);
    if (a) return a.baseStage;
  }
  for (const list of Object.values(APPLICANTS_BY_JOB)) {
    const a = list.find((x) => x.candidateId === candidateId);
    if (a) return a.baseStage;
  }
  return null;
};

// Pipeline stage breakdown for a job (active stages; rejected are excluded).
const JOB_STAGES = [
  { key: "applied", label: "Applied", color: "var(--brand)" },
  { key: "shortlisted", label: "Shortlisted", color: "#93C5FD" },
  { key: "interviewing", label: "Interview", color: "#6366F1" },
  { key: "offer", label: "Offer", color: "#F59E0B" },
  { key: "hired", label: "Hired", color: "#16A34A" },
];
const stageCountsFor = (jobId) => {
  const c = { applied: 0, shortlisted: 0, interviewing: 0, offer: 0, hired: 0 };
  (APPLICANTS_BY_JOB[jobId] || []).forEach((a) => { if (c[a.baseStage] != null) c[a.baseStage]++; });
  return c;
};

// Compact stacked pipeline bar + per-stage counts, shown on a job card.
function JobPipelineBar({ jobId }) {
  const counts = stageCountsFor(jobId);
  const total = JOB_STAGES.reduce((s, st) => s + counts[st.key], 0);
  if (total === 0) return <p className="text-xs" style={{ color: "var(--ink-3)" }}>No one in the pipeline yet.</p>;
  const active = JOB_STAGES.filter((st) => counts[st.key] > 0);
  return (
    <div>
      <div className="flex h-2 rounded-full overflow-hidden gap-0.5" style={{ background: "transparent" }}>
        {JOB_STAGES.map((st) => counts[st.key] > 0 && (
          <div key={st.key} title={`${counts[st.key]} ${st.label}`} style={{ width: `${(counts[st.key] / total) * 100}%`, background: st.color, borderRadius: 9999 }} />
        ))}
      </div>
      <div className="flex flex-wrap gap-x-3 gap-y-1 mt-2">
        {active.map((st) => (
          <span key={st.key} className="inline-flex items-center gap-1 text-[11px]" style={{ color: "var(--ink-2)" }}>
            <span className="w-1.5 h-1.5 rounded-full" style={{ background: st.color }} />
            <span className="tnum font-semibold">{counts[st.key]}</span> {st.label}
          </span>
        ))}
      </div>
    </div>
  );
}

