export default function ResumeAIPreview() {
  const [history, setHistory] = useState(initialHistoryFromUrl);
  const [productSlug, setProductSlug] = useState(() => (typeof window !== "undefined" ? (productSlugFromPath(window.location.pathname) || "") : ""));
  const [solutionSlug, setSolutionSlug] = useState(() => (typeof window !== "undefined" ? (solutionSlugFromPath(window.location.pathname) || "") : ""));
  // Resources: blog post slug + blog category slug (mutually exclusive; both ""
  // = index) and the glossary term slug ("" = index), seeded from the URL.
  const [blogSlug, setBlogSlug] = useState(() => { const i = typeof window !== "undefined" && blogInfoFromPath(window.location.pathname); return i && i.kind === "post" ? i.slug : ""; });
  const [blogCat, setBlogCat] = useState(() => { const i = typeof window !== "undefined" && blogInfoFromPath(window.location.pathname); return i && i.kind === "category" ? i.slug : ""; });
  const [glossarySlug, setGlossarySlug] = useState(() => { const i = typeof window !== "undefined" && glossaryInfoFromPath(window.location.pathname); return i && i.kind === "term" ? i.slug : ""; });
  // Compare: the competitor/alternatives slug ("" = hub), seeded from the URL.
  const [compareSlug, setCompareSlug] = useState(() => { const i = typeof window !== "undefined" && compareInfoFromPath(window.location.pathname); return i && i.kind === "page" ? i.slug : ""; });
  // Trust: the sub-page slug ("" = hub | compliance), seeded from the URL.
  const [trustSlug, setTrustSlug] = useState(() => { const i = typeof window !== "undefined" && trustInfoFromPath(window.location.pathname); return i ? i.slug : ""; });
  // Legal: the document slug, seeded from the URL (defaults to privacy).
  const [legalSlug, setLegalSlug] = useState(() => { const i = typeof window !== "undefined" && legalInfoFromPath(window.location.pathname); return i ? i.slug : "privacy"; });
  const [jobs, setJobs] = useState(MOCK_JOBS);
  // Supabase identity + whether real workspace data has loaded. Writes only go
  // to the DB once a live workspace is loaded, so demo ids never hit the DB.
  const [companyId, setCompanyId] = useState(null);
  const [userId, setUserId] = useState(null);
  const [workspaceLive, setWorkspaceLive] = useState(false);
  const canPersist = hasSupabase && workspaceLive && !!companyId;
  // While true, hold the signed-in app behind a loader so a logged-in user never
  // sees a flash of demo data before their real workspace hydrates on refresh.
  const [restoring, setRestoring] = useState(hasSupabase);
  // Did this page load start with a session token already on disk? If so, a
  // signed-in user is returning, so we hold the Aster splash over ALL screens
  // (including "/", which otherwise renders the public marketing header) until
  // `restoring` clears. Captured once at mount so it can't flip mid-restore.
  const [bootHadSession] = useState(hasStoredAuthSession);
  // We also arrive here mid-auth-transition with no session on disk yet: right
  // after an email-confirmation redirect (Supabase auth tokens in the hash) or a
  // cross-subdomain handoff (#ws_at/#ws_rt). Detect that at mount and hold the
  // splash too, so the confirm -> provision -> forward -> dashboard journey reads
  // as one continuous loading screen instead of flashing login forms between hops.
  const [authTransitionPending] = useState(() => {
    if (typeof window === "undefined") return false;
    return /(ws_at=|ws_rt=|access_token=|refresh_token=|type=signup|type=recovery)/.test(window.location.hash || "");
  });
  // Set while we're forwarding to a workspace subdomain, so the splash stays up
  // through the cross-origin navigation instead of blinking the login form.
  const [redirecting, setRedirecting] = useState(false);
  // Hand off from the pre-boot splash (index.html sets data-app-booting before
  // paint to hide the prerendered marketing shell for signed-in / mid-auth loads).
  // On our first commit we render either the Aster splash (returning user) or the
  // right screen, so clear the flag now: same frame, the boot overlay hides and
  // #root becomes visible — a seamless load, never a flash of marketing.
  useLayoutEffect(() => {
    try { document.documentElement.removeAttribute("data-app-booting"); } catch { /* noop */ }
  }, []);
  // Set when the signed-in owner's workspace is soft-deleted (within the 30-day
  // window). We show the restore screen instead of the app.
  const [deletedInfo, setDeletedInfo] = useState(null);
  // Signed up, but their company already has a workspace. They need an invite, and
  // they need to know who from.
  const [joinBlocked, setJoinBlocked] = useState(null);
  // Email-code 2FA: the account has it on and this device isn't trusted, so the
  // workspace is held behind an emailed code. Holds the email to show on the gate.
  const [pending2fa, setPending2fa] = useState(null);
  const [activeJobId, setActiveJobId] = useState(() => (typeof window !== "undefined" ? (applicantsJobFromPath(window.location.pathname) || "j1") : "j1"));
  // On Launch, only one job stays active; the rest are paused (kept, not
  // deleted). This tracks which one the user chose to keep on downgrade.
  const [keptJobId, setKeptJobId] = useState("j1");
  const [viewCandidateId, setViewCandidateId] = useState(() => (typeof window !== "undefined" ? candidateIdFromPath(window.location.pathname) : null));
  const [viewCandidateJobId, setViewCandidateJobId] = useState(() => (typeof window !== "undefined" ? new URLSearchParams(window.location.search).get("job") : null));
  const [viewCandidateStage, setViewCandidateStage] = useState(null);
  const [candidateFilter, setCandidateFilter] = useState(null);
  const [jobStatusFilter, setJobStatusFilter] = useState(null);
  const [interviewers, setInterviewers] = useState(INITIAL_INTERVIEWERS);
  const [pendingInvites, setPendingInvites] = useState([]); // teammate invites with no profile yet (count toward seats)
  const [jobAssignments, setJobAssignments] = useState([]); // [{ job_id, profile_id }] — job interviewer pools
  // Add/remove a teammate on a job's interviewer pool (admin-only on the server).
  // Optimistic + server; returns an error message or null.
  const assignInterviewer = async (jobId, profileId) => {
    if (hasSupabase) { const err = await dbAssignInterviewer(jobId, profileId); if (err) return err; }
    setJobAssignments((prev) => (prev.some((a) => a.job_id === jobId && a.profile_id === profileId) ? prev : [...prev, { job_id: jobId, profile_id: profileId }]));
    return null;
  };
  const unassignInterviewer = async (jobId, profileId) => {
    if (hasSupabase) { const err = await dbUnassignInterviewer(jobId, profileId); if (err) return err; }
    setJobAssignments((prev) => prev.filter((a) => !(a.job_id === jobId && a.profile_id === profileId)));
    return null;
  };
  const [interviewQuestions, setInterviewQuestions] = useState({}); // { "candidateId:jobId": [questions] }
  // HR generates the AI interview questions once; stored + shared with the pool.
  const generateInterviewQuestions = async (candidateId, jobId, questions) => {
    if (!candidateId || !jobId) return;
    const key = `${candidateId}:${jobId}`;
    setInterviewQuestions((prev) => (prev[key] ? prev : { ...prev, [key]: questions }));
    if (canPersist) await dbSaveInterviewQuestions(companyId, userId, { candidateId, jobId, questions });
  };
  const [scheduleRequests, setScheduleRequests] = useState([]); // [{ application_id, requested_by }] — open interview requests
  // Offer status per candidate: 'sent' | 'accepted' | 'declined'. Sending moves
  // them to the Offer stage; accepting waits for HR to click "Mark as hired".
  const [offers, setOffers] = useState({});
  // When each candidate was hired (YYYY-MM-DD), for the Hired-list month filter.
  const [hiredDates, setHiredDates] = useState({ c8: "2026-06-18" });
  // Interviewer flags a candidate for the hiring manager to schedule. Idempotent:
  // the first request per application wins (server-enforced). Returns error|null.
  const requestScheduling = async (applicationId) => {
    if (!applicationId) return "Missing application.";
    if (hasSupabase) { const err = await dbRequestScheduling(applicationId); if (err) return err; }
    setScheduleRequests((prev) => (prev.some((r) => r.application_id === applicationId) ? prev : [...prev, { application_id: applicationId, requested_by: userId }]));
    return null;
  };
  // Hiring manager marks who actually attended the interview. Persisted onto the
  // interview's attendees jsonb; drives which interviewers must score before a
  // decision unlocks. Optimistic: update local bookings, then write.
  const setAttendance = (candidateId, attendedIds = []) => {
    if (!candidateId) return;
    const set = new Set(attendedIds);
    setBookings((prev) => {
      const b = prev[candidateId];
      if (!b) return prev;
      const attendees = (b.attendees || []).map((a) => ({ ...a, attended: set.has(a.id) }));
      return { ...prev, [candidateId]: { ...b, attendees } };
    });
    if (canPersist) dbSetAttendance(companyId, candidateId, attendedIds);
  };
  // Swap one interviewer on a scheduled interview for another (drop-out cover).
  // Replaces the attendee in the booking's panel, keeping any attended flag off
  // for the newcomer, and persists the whole panel.
  const substituteAttendee = (candidateId, oldId, replacement, fallbackJobId = null) => {
    if (!candidateId || !oldId || !replacement?.id) return;
    let nextAttendees = null;
    let bookingJobId = null;
    setBookings((prev) => {
      const b = prev[candidateId];
      if (!b) return prev;
      bookingJobId = b.jobId || null;
      const attendees = (b.attendees || []).map((a) => (a.id === oldId ? { id: replacement.id, name: replacement.name, email: replacement.email } : a));
      nextAttendees = attendees;
      return { ...prev, [candidateId]: { ...b, attendees } };
    });
    // The interview's own job_id can be null; fall back to the job the candidate
    // is being viewed under, so we always know which job to grant access to.
    const jobId = bookingJobId || fallbackJobId || null;
    if (canPersist && nextAttendees) {
      dbSetInterviewAttendees(companyId, candidateId, nextAttendees);
      // The panel swap alone doesn't grant access: assign the new interviewer to
      // the job so the candidate, the interview and the scorecard show up in THEIR
      // dashboard (RLS scopes interviewers to jobs they're assigned to).
      if (jobId) {
        dbAssignInterviewer(jobId, replacement.id);
        setJobAssignments((prev) => (prev.some((x) => x.job_id === jobId && x.profile_id === replacement.id) ? prev : [...prev, { job_id: jobId, profile_id: replacement.id }]));
        // Email the new interviewer that they're on the panel (best-effort).
        if (hasSupabase) supabase.functions.invoke("notify-panel-added", { body: { candidate_id: candidateId, job_id: jobId, interviewer_id: replacement.id } }).catch(() => {});
      }
    }
  };
  const [scorecards, setScorecards] = useState(SCORECARDS_BY_CANDIDATE);
  const addScorecard = (candidateId, card, jobId = null) => {
    // Stamp the author's id so the panel can tell whose card is whose (and gate
    // the blind-until-submit view). job_id is required for the interviewer RLS
    // insert policy (job_id in assigned_job_ids()).
    const stamped = { ...card, interviewerId: userId };
    setScorecards((prev) => ({ ...prev, [candidateId]: [...(prev[candidateId] || []), stamped] }));
    if (canPersist) dbAddScorecard(companyId, userId, { candidateId, jobId, ratings: card.ratings, notes: card.notes });
  };
  const [avatarUrl, setAvatarUrl] = useState(null);
  const [companyLogoUrl, setCompanyLogoUrl] = useState(null);
  // Global platform feature flags, set from /admin (public read). Default off so
  // SSO and white-label stay disabled until an admin turns them on.
  const [platformFlags, setPlatformFlags] = useState({ sso_login: false, white_label: false });
  useEffect(() => {
    if (!hasSupabase) return;
    let active = true;
    supabase.from("platform_flags").select("key, enabled").then(({ data }) => {
      if (active && Array.isArray(data) && data.length) {
        setPlatformFlags((prev) => { const next = { ...prev }; data.forEach((f) => { next[f.key] = !!f.enabled; }); return next; });
      }
    });
    return () => { active = false; };
  }, []);
  // White-label gate: the custom company logo only applies platform-wide when
  // white-label is enabled; otherwise the default Aster brand shows everywhere.
  const logoUrl = platformFlags.white_label ? companyLogoUrl : null;
  const [defaultProvider, setDefaultProvider] = useState("google");
  // Calendar is connected once at the workspace level (single Google Workspace /
  // Microsoft 365 tenant), rather than per interviewer. Powers availability +
  // event creation for everyone.
  // No calendar OAuth exists yet, so nothing can be connected. Defaulting this to
  // `true` made the app claim a live calendar and underpinned the fake slot finder.
  const [calendarConnected, setCalendarConnected] = useState(false);
  // User profile, the greeting, sidebar and settings all read from this.
  const [profile, setProfile] = useState({ firstName: "Shah", lastName: "Ramly", role: "Hiring Manager" });
  const [company, setCompany] = useState("Oryx Studio");
  // Company billing details (address + registration number), edited on the
  // Profile screen and shown on invoices. Hydrated from the companies row.
  const [companyAddress, setCompanyAddress] = useState("");
  // Structured billing address (source of truth for the Profile form); the
  // joined `companyAddress` string above is derived from it for invoices.
  const [companyAddressParts, setCompanyAddressParts] = useState({ ...EMPTY_ADDRESS });
  const [companyRegNo, setCompanyRegNo] = useState("");
  const [plan, setPlan] = useState("scale");
  const [planCycle, setPlanCycle] = useState("monthly");
  // Both hydrated from subscriptions on sign-in: days left when status is
  // 'trialing' (0 otherwise), and the current_period_end the plan renews on.
  const [trialDaysLeft, setTrialDaysLeft] = useState(0);
  const [renewsAt, setRenewsAt] = useState(null);
  const [subStatus, setSubStatus] = useState(null); // subscriptions.status
  const trialActive = trialDaysLeft > 0;
  // A live trial grants Scale-level access whatever tier the row carries.
  const effectivePlan = trialActive && plan === "launch" ? "scale" : plan;
  // Shared monthly AI-match run counter (Free is limited; resets in production
  // each billing period, here it's per session).
  const [matchRunsUsed, setMatchRunsUsed] = useState(0);
  // The signed-in user's own candidate shortlist (starred application ids). Keyed
  // by application, independent of AI Rank order and pipeline stage, so a re-rank
  // never loses a reviewer's picks.
  const [shortlistedApps, setShortlistedApps] = useState(() => new Set());
  const [aiRankResetsAt, setAiRankResetsAt] = useState(null); // next 30-day credit reset (from signup)
  // Job posting is a concurrent OPEN-role limit (plan maxJobs), not a monthly
  // credit: closing a role frees a slot, reopening takes one. Derived live from
  // the jobs list so posting/closing updates the meter at once. resetsAt stays
  // null (jobs never reset); AI Rank / parses / insights keep their monthly cycles.
  const jobLimit = (() => { const m = planLimits(effectivePlan).maxJobs; return m === Infinity ? null : m; })();
  const openJobsCount = jobs.filter((j) => j.status === "open").length;
  const jobPostUsage = { used: openJobsCount, limit: jobLimit, resetsAt: null };
  // AI Parsing (bulk upload) credits for the current 30-day cycle.
  const [parseUsage, setParseUsage] = useState({ used: 0, limit: null, resetsAt: null });
  // Applicant parses are a separate allowance from bulk upload, metered separately.
  const [applicantParseUsage, setApplicantParseUsage] = useState({ used: 0, limit: null, resetsAt: null });
  // Persistent "Recent imports" log (loaded from import_runs on hydrate).
  const [importHistory, setImportHistory] = useState([]);
  // Save a finished bulk-import run: optimistic prepend, then persist + reconcile id.
  const saveImportRun = async (run) => {
    setImportHistory((h) => [run, ...h]);
    if (!hasSupabase || !companyId) return;
    const saved = await dbSaveImportRun(companyId, userId, run);
    if (saved) setImportHistory((h) => h.map((r) => (r === run ? saved : r)));
  };
  // Blocked from publishing when the workspace is already at its open-role limit.
  const jobPostBlocked = jobLimit != null && openJobsCount >= jobLimit;
  // No-op: the open-role meter is derived from `jobs`, so it updates itself the
  // moment a role is published or closed. Kept as a prop for the job screens.
  const consumeJobPost = () => {};
  const [aiInsightsUsed, setAiInsightsUsed] = useState(0);
  // Generated AI insights, kept for the session (candidate id -> insights).
  const [insightsCache, setInsightsCache] = useState({});
  // See Why (Option B): its own metered credit, charged once per candidate and
  // cached (candidate id -> rationale). Regenerating charges again via a prompt.
  // Plan a visitor picked on the marketing site, carried into sign-up.
  const [signupPlan, setSignupPlan] = useState("elite");
  const [signupCycle, setSignupCycle] = useState("monthly");
  // true = arrived via a generic "start trial" CTA (14-day Growth trial);
  // false = picked a specific plan on the pricing table (pay / free forever).
  const [signupTrial, setSignupTrial] = useState(true);
  // Shared activity feed. Both the header notification bell and the
  // dashboard "Recent Activity" card read from this list; `read` drives
  // the unread badge on the bell.
  // profiles.activities_seen_at — the watermark the unread badge is measured against.
  const [activitiesSeenAt, setActivitiesSeenAt] = useState(null);
  const [activities, setActivities] = useState(() => buildActivities(null));
  // Persist the watermark so the badge does not come back on reload. Optimistic:
  // the bell clears immediately, and a failed write is logged, not shown — a
  // stale badge is a far smaller problem than a modal over a notification list.
  const markActivitiesRead = async () => {
    setActivities((list) => list.map((a) => ({ ...a, read: true })));
    if (!hasSupabase) return;
    const { data, error } = await supabase.rpc("mark_activities_seen");
    if (error) { console.error("mark_activities_seen failed:", error.message || error); return; }
    setActivitiesSeenAt(data || new Date().toISOString());
  };
  // Dashboard date range, defaults to today (current date).
  const today0 = startOfDay(new Date());
  const [dateRange, setDateRange] = useState({ start: today0, end: today0 });
  const [previewRequest, setPreviewRequest] = useState(null);
  // The job whose public application page we're previewing (via a job's apply link).
  const [previewApplyJob, setPreviewApplyJob] = useState(null);
  // Public apply page (someone opened /apply/<jobId> from the outside, no login).
  const [publicApply, setPublicApply] = useState(null); // { id, status: loading|ok|notfound, job?, company? }
  // Booking state per candidate, shared across the profile and the public
  // booking preview: { [candidateId]: { status, confirmedSlot, request } }.
  // status: 'sent' (invite out) | 'scheduled' (candidate confirmed a time).
  // Empty by default (no mock): real confirmed interviews hydrate from Supabase
  // via setBookings on login, and new ones the user books appear alongside.
  const [bookings, setBookings] = useState({});
  // Stage overrides applied after the initial mock stage, keyed by candidate id.
  // Lets actions elsewhere (like a confirmed booking) advance the pipeline stage.
  const [stageOverrides, setStageOverrides] = useState({});
  // Search view state (tab, filters, page, results, scroll) kept across the
  // profile round-trip so Back returns to the same place, not a fresh list.
  const searchStateRef = useRef({});

  const rawScreen = history[history.length - 1];
  // Interviewer RBAC guard: interviewers may only open their assigned interviews,
  // the candidate profiles they scorecard, and their own profile. Any other
  // workspace screen (deep-link, stale history, the emailed link) resolves to
  // their Interviews home instead of rendering. Owner/admin are unaffected, and
  // the mock/demo role ("Hiring Manager") is not an interviewer, so the preview
  // is untouched. This mirrors the server: RLS already scopes their data.
  const screen =
    canPersist && isInterviewer(profile?.role) &&
    WORKSPACE_SCREENS.has(rawScreen) && !INTERVIEWER_ALLOWED.has(rawScreen)
      ? "interviews"
      : rawScreen;
  const [newJobOpen, setNewJobOpen] = useState(false);
  const [requestRoleOpen, setRequestRoleOpen] = useState(false); // interviewer's "Request a role" modal
  // Hiring manager approves / rejects an interviewer's role request. Approving
  // publishes the role right away (status "open") so it isn't a two-step
  // approve-then-publish. If the workspace is at its open-role limit, it lands as
  // an approved draft to publish once a slot frees. Rejecting just marks it.
  const decideJobRequest = async (jobId, approve) => {
    const j = jobs.find((x) => x.id === jobId);
    if (!j) return;
    const approvalStatus = approve ? "approved" : "rejected";
    const publishNow = approve && !jobPostBlocked;
    setJobs((prev) => prev.map((x) => (x.id === jobId
      ? { ...x, approvalStatus, status: publishNow ? "open" : x.status, ...(publishNow && !x.posted_at ? { posted_at: new Date().toISOString() } : {}) }
      : x)));
    if (canPersist) {
      const clean = { ...j, approvalStatus };
      delete clean.posted_at; delete clean.viewStats; // derived on load, not stored in details
      dbUpdateJob(jobId, clean);
      if (publishNow) {
        // dbSetJobStatus runs trg_charge_job_post, which enforces the open-role
        // limit server-side. If it refuses, fall back to an approved draft.
        const res = await dbSetJobStatus(jobId, "open");
        if (res?.error) setJobs((prev) => prev.map((x) => (x.id === jobId ? { ...x, status: "draft" } : x)));
      }
      // Email the interviewer who requested the role with the decision (best-effort).
      supabase.functions.invoke("notify-role-request", { body: { job_id: jobId, event: approvalStatus } }).catch(() => {});
    }
  };

  // Public apply link: fetch the job's public details and record a view. Only
  // runs on a real /apply/<id> visit (not the in-app admin preview, which sets
  // previewApplyJob), so admin previews never inflate the view count.
  useEffect(() => {
    if (screen !== "apply" || previewApplyJob) return;
    const id = applyJobFromPath(window.location.pathname);
    if (!id || publicApply?.id === id) return;
    setPublicApply({ id, status: "loading" });
    (async () => {
      if (!hasSupabase) { setPublicApply({ id, status: "notfound" }); return; }
      const { data, error } = await supabase.rpc("get_public_job", { p_job_id: id });
      const row = Array.isArray(data) ? data[0] : data;
      if (error || !row) { setPublicApply({ id, status: "notfound" }); return; }
      const job = { id: row.id, title: row.title, status: row.status, expires_at: row.expires_at, ...(row.details || {}) };
      setPublicApply({ id, status: "ok", job, company: row.company_name || "", logoUrl: row.logo_url || null });
      // Record the visit: unique per browser per day, tagged with ?source=.
      let source = null, vid = null;
      try { source = new URLSearchParams(window.location.search).get("source"); } catch { /* ignore */ }
      try {
        vid = localStorage.getItem("aster_vid");
        if (!vid) { vid = Math.random().toString(36).slice(2) + Date.now().toString(36); localStorage.setItem("aster_vid", vid); }
      } catch { /* private mode / storage blocked, still record the view, just no dedup */ }
      // Must await (or .then), the supabase query builder is lazy and won't send
      // the request otherwise. Best-effort, so swallow any error.
      try { await supabase.rpc("track_job_view", { p_job_id: id, p_visitor: vid, p_source: source }); } catch { /* ignore */ }
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [screen, previewApplyJob]);

  // Public interview booking page (candidate opened /book/<token> from an email,
  // no login). Preview the invite so we can render the proposed times.
  const [publicBooking, setPublicBooking] = useState(null); // { token, status: loading|notfound|ok|done, data? }
  useEffect(() => {
    if (screen !== "bookInterview" || typeof window === "undefined") return;
    const token = bookTokenFromPath(window.location.pathname);
    if (!token || publicBooking?.token === token) return;
    setPublicBooking({ token, status: "loading" });
    (async () => {
      if (!hasSupabase) { setPublicBooking({ token, status: "notfound" }); return; }
      const { data, error } = await supabase.rpc("book_interview_preview", { p_token: token });
      const row = Array.isArray(data) ? data[0] : data;
      if (error || !row) { setPublicBooking({ token, status: "notfound" }); return; }
      setPublicBooking({ token, status: row.status === "scheduled" ? "done" : "ok", data: row });
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [screen]);

  // Candidate picked a slot: persist + notify via the confirm-booking function.
  const confirmPublicBooking = async (start) => {
    if (!publicBooking?.token) return { ok: false };
    const { data, error } = await supabase.functions.invoke("confirm-booking", { body: { token: publicBooking.token, start } });
    if (error || data?.error) return { ok: false, error: data?.error || error?.message || "Could not confirm this time." };
    setPublicBooking((p) => ({ ...p, status: "done", data: { ...p.data, status: "scheduled", scheduled_at: start } }));
    return { ok: true };
  };

  // Public offer accept/decline page (candidate opened /offer/<token>, no login).
  const [publicOffer, setPublicOffer] = useState(null); // { token, status: loading|notfound|ok|done, data? }
  useEffect(() => {
    if (screen !== "publicOffer" || typeof window === "undefined") return;
    const token = offerTokenFromPath(window.location.pathname);
    if (!token || publicOffer?.token === token) return;
    setPublicOffer({ token, status: "loading" });
    (async () => {
      if (!hasSupabase) { setPublicOffer({ token, status: "notfound" }); return; }
      const { data, error } = await supabase.rpc("offer_preview", { p_token: token });
      const row = Array.isArray(data) ? data[0] : data;
      if (error || !row) { setPublicOffer({ token, status: "notfound" }); return; }
      setPublicOffer({ token, status: row.status === "sent" ? "ok" : "done", data: row });
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [screen]);

  // Candidate accepted or declined: record + notify via the respond-offer function.
  const respondPublicOffer = async (response) => {
    if (!publicOffer?.token) return { ok: false };
    const { data, error } = await supabase.functions.invoke("respond-offer", { body: { token: publicOffer.token, response } });
    if (error || data?.error) return { ok: false, error: data?.error || error?.message || "Could not record your response." };
    setPublicOffer((p) => ({ ...p, status: "done", data: { ...p.data, status: response } }));
    return { ok: true };
  };

  // Central scroll management: forward navigation starts the new screen at the
  // top; Back restores the scroll position of the screen you're returning to.
  // Positions are keyed by stack depth (one entry per screen in the history).
  const scrollByDepth = useRef({});
  const routeTimer = useRef(null);
  const prevDepthRef = useRef(history.length);
  const prevTopRef = useRef(history[history.length - 1]);
  // Take over scroll from the browser so our forward/back logic isn't overridden.
  useEffect(() => {
    if (typeof window !== "undefined" && "scrollRestoration" in window.history) window.history.scrollRestoration = "manual";
  }, []);
  useLayoutEffect(() => {
    const prev = prevDepthRef.current;
    const cur = history.length;
    const top = history[history.length - 1];
    if (typeof window !== "undefined") {
      if (cur > prev) window.scrollTo(0, 0);                                   // forward → top
      else if (cur < prev) window.scrollTo(0, scrollByDepth.current[cur] || 0); // back → restore
      else if (top !== prevTopRef.current) window.scrollTo(0, 0);              // same depth, screen swapped → top
    }
    prevDepthRef.current = cur;
    prevTopRef.current = top;
  }, [history]);

  // Keep document metadata in sync with the current route so each marketing
  // page has its own title, description and canonical (crawlers render JS).
  useEffect(() => {
    if (typeof document === "undefined") return;
    const meta = routeMeta(screen, productSlug, solutionSlug, blogSlug, blogCat, glossarySlug, compareSlug, trustSlug, legalSlug);
    document.title = meta.title;
    const setMeta = (selector, attr, key, value) => {
      let el = document.head.querySelector(selector);
      if (!el) {
        el = document.createElement("meta");
        el.setAttribute(attr, key);
        document.head.appendChild(el);
      }
      el.setAttribute("content", value);
    };
    setMeta('meta[name="description"]', "name", "description", meta.description);
    setMeta('meta[property="og:title"]', "property", "og:title", meta.title);
    setMeta('meta[property="og:description"]', "property", "og:description", meta.description);
    setMeta('meta[name="twitter:title"]', "name", "twitter:title", meta.title);
    setMeta('meta[name="twitter:description"]', "name", "twitter:description", meta.description);
    const url = SITE_ORIGIN + meta.path;
    setMeta('meta[property="og:url"]', "property", "og:url", url);
    let link = document.head.querySelector('link[rel="canonical"]');
    if (!link) {
      link = document.createElement("link");
      link.setAttribute("rel", "canonical");
      document.head.appendChild(link);
    }
    link.setAttribute("href", url);

    // Per-page structured data: BlogPosting for articles, DefinedTerm for
    // glossary entries. Removed on pages that don't need it (the site-wide
    // Organization/WebSite graph lives statically in index.html).
    let ld = null;
    if (screen === "blog" && blogSlug) {
      const post = BLOG_POSTS.find((p) => p.slug === blogSlug);
      if (post) ld = {
        "@context": "https://schema.org", "@type": "BlogPosting",
        headline: post.title, description: post.excerpt,
        datePublished: post.date, dateModified: post.date,
        author: { "@type": "Person", name: post.author.name, jobTitle: post.author.role },
        publisher: { "@type": "Organization", name: "Aster", logo: { "@type": "ImageObject", url: SITE_ORIGIN + "/aster-mark.svg" } },
        image: SITE_ORIGIN + "/og-image.svg",
        mainEntityOfPage: { "@type": "WebPage", "@id": url },
        keywords: (post.tags || []).join(", "),
      };
    } else if (screen === "glossary" && glossarySlug) {
      const t = GLOSSARY_TERMS.find((g) => g.slug === glossarySlug);
      if (t) ld = {
        "@context": "https://schema.org", "@type": "DefinedTerm",
        name: t.term, description: t.short, url,
        inDefinedTermSet: { "@type": "DefinedTermSet", name: "Aster Recruiting Glossary", url: SITE_ORIGIN + "/resources/glossary" },
      };
    }
    let ldEl = document.getElementById("ld-page");
    if (ld) {
      if (!ldEl) { ldEl = document.createElement("script"); ldEl.id = "ld-page"; ldEl.type = "application/ld+json"; document.head.appendChild(ldEl); }
      ldEl.textContent = JSON.stringify(ld);
    } else if (ldEl) {
      ldEl.remove();
    }
  }, [screen, productSlug, solutionSlug, blogSlug, blogCat, glossarySlug, compareSlug, trustSlug, legalSlug]);

  const navigate = (target, path) => {
    // Remember where we are before leaving, so Back can restore it.
    if (typeof window !== "undefined" && target !== "newJob") scrollByDepth.current[history.length] = window.scrollY;
    // Fade-through: snap the splash overlay on to cover the screen swap, then drop
    // it after the new screen has committed so the header never flashes between
    // pages. Driven via a DOM attribute (index.html owns the overlay) so it works
    // no matter which render branch the app takes. Modals aren't a page change.
    if (typeof window !== "undefined" && target !== "newJob") {
      const el = document.documentElement;
      try { el.setAttribute("data-route-transition", ""); } catch { /* noop */ }
      clearTimeout(routeTimer.current);
      routeTimer.current = setTimeout(() => { try { el.removeAttribute("data-route-transition"); } catch { /* noop */ } }, 220);
    }
    if (target === "newJob") {
      // New Job is a modal overlay, not a routed screen.
      setNewJobOpen(true);
    } else if (target === -1) {
      // Let the browser drive the pop so the phone Back button stays in sync.
      if (typeof window !== "undefined" && window.history.state && window.history.state.aster) window.history.back();
      else setHistory((h) => (h.length > 1 ? h.slice(0, -1) : h));
    } else if (target === "login") {
      setHistory(["login"]);
      if (typeof window !== "undefined") { window.history.pushState({ aster: true }, "", SCREEN_TO_PATH.login); window.scrollTo(0, 0); }
    } else if ((target === "product" || target === "solutions" || target === "blog" || target === "glossary" || target === "compare") && target === screen) {
      // Re-navigating within the same marketing section (solution → solution,
      // product → product): replace the current entry instead of stacking
      // another same-named one. The name-based history stack can't tell two
      // "solutions" entries apart, so stacking them corrupts Back/redirect. The
      // caller has already set the slug, which re-renders; scroll to top like a
      // forward move.
      if (typeof window !== "undefined") { window.history.replaceState({ aster: true }, "", path || SCREEN_TO_PATH[target] || "/"); window.scrollTo(0, 0); }
    } else {
      setHistory((h) => [...h, target]);
      if (typeof window !== "undefined") window.history.pushState({ aster: true }, "", path || SCREEN_TO_PATH[target] || "/");
    }
  };

  // Apply a loaded Supabase session to the workspace, then route in. In mock
  // mode (no keys) sess is null and the demo profile is left untouched.
  const applyCustomerSession = (sess, dest = "dashboard") => {
    // Multi-tenant: if this workspace lives on its own subdomain and we're not
    // there yet, forward (with a session handoff) instead of loading here.
    if (needsWorkspaceRedirect(sess)) { setRedirecting(true); return; }
    if (sess) {
      setProfile(sess.profile);
      setCompany(sess.company);
      setCompanyLogoUrl(sess.logoUrl || null);
      setCompanyAddress(sess.address || "");
      setCompanyAddressParts(sess.addressParts || { ...EMPTY_ADDRESS });
      setCompanyRegNo(sess.registrationNo || "");
      if (sess.plan) setPlan(sess.plan);
      setPlanCycle(sess.planCycle || "monthly");
      setTrialDaysLeft(sess.trialDaysLeft || 0);
      setRenewsAt(sess.renewsAt || null);
      setSubStatus(sess.subStatus || null);
      setActivitiesSeenAt(sess.activitiesSeenAt || null);
      if (sess.calendarProvider) setProvider(sess.calendarProvider);
      if (sess.avatarPath) signedAvatarUrl(sess.avatarPath).then((u) => u && setAvatarUrl(u));
      if (sess.companyId) { setCompanyId(sess.companyId); setUserId(sess.userId); hydrateWorkspace(sess.companyId, { seenAt: sess.activitiesSeenAt }); }
    }
    // Interviewers have no dashboard/billing; land them on their Interviews home.
    navigate(isInterviewer(sess?.profile?.role) ? "interviews" : dest);
  };

  // Replace the demo datasets with the signed-in company's real rows. A no-op
  // (keeps demo data) for an empty workspace or when Supabase isn't configured.
  // Re-fetch just the team (members + pending invites) with their real DB ids,
  // so row actions (Remove, Revoke) target real rows instead of the optimistic
  // placeholder ids an invite would otherwise add.
  const reloadTeam = async () => {
    if (!hasSupabase || !companyId) return;
    const [{ data: profs }, { data: invs }] = await Promise.all([
      supabase.from("profiles").select("id, full_name, email, role, status").eq("company_id", companyId).neq("status", "suspended"),
      supabase.from("invitations").select("id, email, role").eq("company_id", companyId).is("accepted_at", null).gt("expires_at", new Date().toISOString()),
    ]);
    setInterviewers((profs || []).map((p) => ({ id: p.id, name: p.full_name || "Interviewer", email: p.email || "", role: p.role, pending: p.status === "invited", timezone: "Asia/Kuala_Lumpur" })));
    setPendingInvites((invs || []).map((v) => ({ id: v.id, email: v.email || "", role: v.role || "interviewer" })));
  };

  // The signed-in user's own candidate shortlist. Loaded once identity is known
  // (companyId + userId), and refreshed if either changes.
  useEffect(() => {
    if (!hasSupabase || !companyId || !userId) return;
    let alive = true;
    dbListMyShortlist(companyId, userId).then((ids) => { if (alive) setShortlistedApps(new Set(ids)); });
    return () => { alive = false; };
  }, [companyId, userId]);

  // Star / unstar a candidate for the signed-in user (optimistic; persisted).
  const toggleShortlist = (applicationId) => {
    if (!applicationId) return;
    const on = !shortlistedApps.has(applicationId);
    setShortlistedApps((prev) => { const next = new Set(prev); if (on) next.add(applicationId); else next.delete(applicationId); return next; });
    if (canPersist) dbSetShortlist(companyId, userId, applicationId, on);
  };

  const hydrateWorkspace = async (companyId, opts = {}) => {
    // Load this month's AI Rank credit usage for the meter (per company).
    if (hasSupabase) {
      supabase.rpc("get_ai_rank_usage").then(({ data, error }) => {
        if (error) { console.error("get_ai_rank_usage failed:", error.message || error); return; }
        const row = Array.isArray(data) ? data?.[0] : data;
        if (!row) { console.warn("get_ai_rank_usage returned no row (no company for this session?)"); return; }
        if (typeof row.used === "number") setMatchRunsUsed(row.used);
        if (row.resets_at) setAiRankResetsAt(row.resets_at);
      }).catch((e) => console.error("get_ai_rank_usage threw:", e));
      // AI Insight credits. Never hydrated before 0046 added the counter, so the
      // cap silently reset to zero on every page load.
      supabase.rpc("get_ai_insight_usage").then(({ data, error }) => {
        if (error) { console.error("get_ai_insight_usage failed:", error.message || error); return; }
        const row = Array.isArray(data) ? data?.[0] : data;
        if (row && typeof row.used === "number") setAiInsightsUsed(row.used);
      }).catch((e) => console.error("get_ai_insight_usage threw:", e));
      // Job posting is a concurrent open-role limit now, derived from the jobs
      // list on the client, so there's no per-cycle usage to load here.
      // AI Parsing (bulk upload) credits for this cycle.
      supabase.rpc("get_resume_parse_usage").then(({ data, error }) => {
        if (error) { console.error("get_resume_parse_usage failed:", error.message || error); return; }
        const row = Array.isArray(data) ? data?.[0] : data;
        if (row) setParseUsage({ used: Number(row.used) || 0, limit: row.monthly_limit ?? null, resetsAt: row.resets_at || null });
      }).catch((e) => console.error("get_resume_parse_usage threw:", e));
      // Applicant parses (public job applications) for this cycle. A separate pool
      // from bulk upload above, and the one the pricing page actually sells.
      supabase.rpc("get_applicant_parse_usage").then(({ data, error }) => {
        if (error) { console.error("get_applicant_parse_usage failed:", error.message || error); return; }
        const row = Array.isArray(data) ? data?.[0] : data;
        if (row) setApplicantParseUsage({ used: Number(row.used) || 0, limit: row.monthly_limit ?? null, resetsAt: row.resets_at || null });
      }).catch((e) => console.error("get_applicant_parse_usage threw:", e));
      // Persistent "Recent imports" history for the Bulk Upload screen.
      // Skip on a post-import refresh: the just-finished run was already added
      // optimistically + persisted, so reloading here would race it and wipe it.
      if (!opts.keepImportHistory) {
        dbListImportRuns(companyId).then(setImportHistory).catch((e) => console.error("dbListImportRuns threw:", e));
      }
    }
    const data = await loadWorkspaceData(companyId);
    if (!data) return;
    applyWorkspaceData(data);          // swaps candidates / applicants / matches
    setJobs(data.jobs);
    // Keep the job the URL points at (e.g. /applicants/<id> on refresh); only
    // fall back to the first job when the current id isn't a real one.
    setActiveJobId((cur) => (data.jobs.some((j) => j.id === cur) ? cur : (data.jobs[0]?.id || cur)));
    setBookings(data.bookings);
    setScorecards(data.scorecards);
    if (data.interviewers?.length) setInterviewers(data.interviewers);
    setPendingInvites(data.pendingInvites || []);
    setJobAssignments(data.jobAssignments || []);
    setScheduleRequests(data.scheduleRequests || []);
    setInterviewQuestions(data.interviewQuestions || {});
    setOffers(data.offers || {});
    setActivities(buildActivities(opts.seenAt ?? activitiesSeenAt));  // rebuilt from the now-real datasets
    setWorkspaceLive(true);            // real ids now in play → writes persist
  };

  // Keep the open workspace fresh without a manual reload. New applicants land in
  // the DB from the public apply flow while the recruiter is elsewhere in the app,
  // so re-hydrate when the tab regains focus or becomes visible, and poll gently
  // while it's open and visible. (No Supabase realtime publication is configured,
  // so this is the reliable path; it replaces "refresh the page to see them".)
  useEffect(() => {
    if (!hasSupabase || !canPersist || !companyId) return;
    const refresh = () => { if (document.visibilityState === "visible") hydrateWorkspace(companyId); };
    window.addEventListener("focus", refresh);
    document.addEventListener("visibilitychange", refresh);
    const id = setInterval(refresh, 45000);
    return () => {
      window.removeEventListener("focus", refresh);
      document.removeEventListener("visibilitychange", refresh);
      clearInterval(id);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [canPersist, companyId]);

  // Sign out for real when Supabase is wired, then reset to defaults and return
  // to the login screen.
  const handleSignOut = async () => {
    if (hasSupabase) {
      try { await supabase.auth.signOut(); } catch { /* ignore */ }
      // Hard navigation so the swapped-in workspace data can't leak to the next
      // person who uses this tab; a fresh load resets all module state to demo.
      if (typeof window !== "undefined") { window.location.assign("/login"); return; }
    }
    setProfile({ firstName: "Shah", lastName: "Ramly", role: "Hiring Manager" });
    setCompany("Oryx Studio");
    setPlan("scale");
    navigate("login");
  };

  // Ending a trial is not a downgrade: there is no free tier to fall back to.
  // end_trial_now() suspends the workspace and opens the same 30-day soft-delete
  // window the nightly cron uses, so the reload lands on the subscribe paywall.
  // The caller owns the confirmation step. Resolves to an error string to display,
  // or null on success (in which case the reload takes over).
  const endTrial = async () => {
    if (!hasSupabase) { setTrialDaysLeft(0); return null; } // demo build, nothing to suspend
    const { error } = await supabase.rpc("end_trial_now");
    if (error) {
      console.error("end_trial_now failed:", error);
      // 42883 = function does not exist: migration 0039 hasn't been applied.
      if (error.code === "42883" || /function .*end_trial_now.* does not exist|could not find the function/i.test(error.message || "")) {
        return "Run migration 0039 first: the end_trial_now function doesn't exist in this database yet.";
      }
      return error.message || "Couldn't end the trial.";
    }
    if (typeof window !== "undefined") window.location.assign("/");
    return null;
  };

  // A pending teammate invite from the emailed link (/?invite=<token>). Previewed
  // server-side (invite_preview) so we can greet the invitee and lock the email
  // before they create an account or sign in.
  const [invite, setInvite] = useState(null);
  useEffect(() => {
    if (typeof window === "undefined" || !hasSupabase) return;
    const token = new URLSearchParams(window.location.search).get("invite");
    if (!token) return;
    let alive = true;
    supabase.rpc("invite_preview", { p_token: token }).then(async ({ data }) => {
      if (!alive) return;
      const row = Array.isArray(data) ? data[0] : data;
      if (!row || !row.email) return;
      const inviteEmail = String(row.email).toLowerCase();
      // If the invitee is already authenticated as this same address (they just
      // clicked the email-confirmation link, which redirects back here with a
      // session), don't show the create-account form again — the auth bootstrap
      // redeems the invite and drops them into the workspace.
      const { data: sdata } = await supabase.auth.getSession();
      if (!alive) return;
      if (sdata?.session?.user?.email?.toLowerCase() === inviteEmail) return;
      setInvite({ token, email: inviteEmail, company: row.company_name, role: row.role });
      navigate("acceptInvite", `/?invite=${encodeURIComponent(token)}`);
    });
    return () => { alive = false; };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Restore a signed-in customer on load so the workspace greets them by their
  // real name / company / plan. Admins have no profile row, so they're ignored.
  useEffect(() => {
    if (!hasSupabase) return; // restoring stays false → mock/marketing renders as-is
    let cancelled = false;
    let handled = null; // guard so the same user isn't restored twice

    const applySession = async (session) => {
      if (cancelled) return;
      if (!session) {
        setRestoring(false);
        // W4: no session. If this load deep-linked into a workspace-only screen,
        // send the visitor to /login rather than leaving the app shell to render
        // over demo data. Public screens (marketing/apply/booking) are untouched.
        if (typeof window !== "undefined" && WORKSPACE_SCREENS.has(screenFromPath(window.location.pathname))) {
          navigate("login");
        }
        return;
      }
      const email = session.user.email || "";
      // Google / Microsoft (any non-password) sign-ins are restricted to work
      // domains. hd/tenant hints don't hard-block personal accounts, so we
      // enforce it here: reject the session and bounce to /login with an error.
      const provider = session.user.app_metadata?.provider;
      const isSSO = provider !== "email"; // google/azure/undefined all gate; only password is exempt
      if (isSSO && !isBusinessEmail(email)) {
        await supabase.auth.signOut();
        if (typeof window !== "undefined") window.location.assign("/login?sso_error=domain");
        return;
      }
      // Two-factor gate: if this account has TOTP enrolled but the session is
      // still aal1 (fresh password or SSO sign-in), hold the workspace and send
      // them to the login screen, which auto-shows the 6-digit code prompt.
      const { data: aalNow } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
      if (aalNow && aalNow.nextLevel === "aal2" && aalNow.currentLevel === "aal1") {
        if (cancelled) return;
        setRestoring(false);
        navigate("login");
        return;
      }
      // Soft-deleted workspace: within the 30-day window it stops resolving under
      // RLS, so show the restore screen instead of an empty/broken app.
      try {
        const { data: delRows } = await supabase.rpc("my_deletion_status");
        const del = Array.isArray(delRows) ? delRows[0] : delRows;
        if (del && del.deleted_at) {
          if (cancelled) return;
          setDeletedInfo(del);
          setRestoring(false);
          return;
        }
      } catch { /* RPC missing / offline: fall through to normal load */ }

      if (handled === session.user.id) return; // already restored this user
      handled = session.user.id;
      try {
        let sess = await loadCustomerSession(session.user.id, email);
        // Returning to accept a teammate invite (e.g. after email confirmation):
        // if the URL still carries the token and this user has no workspace yet,
        // redeem it before falling back to SSO provisioning.
        const inviteTok = typeof window !== "undefined" ? new URLSearchParams(window.location.search).get("invite") : null;
        let joinedViaInvite = false;
        if (!sess && inviteTok) {
          const { error: accErr } = await supabase.rpc("accept_invite", { p_token: inviteTok });
          if (!accErr || /already exists/i.test(accErr.message)) { sess = await loadCustomerSession(session.user.id, email); joinedViaInvite = true; }
        }
        // First-time user with no workspace yet (a just-confirmed password signup
        // lands here already authed, and so does a fresh SSO sign-in): provision
        // one. Prefer the company name + slug chosen at signup (auth metadata);
        // fall back to a name derived from the work-email domain so any business
        // email always ends up in a workspace instead of a dead-end.
        if (!sess && isBusinessEmail(email)) {
          const cn = session.user.user_metadata?.company_name || companyFromEmail(email);
          const rpcErr = await createCompanyAndWelcome(
            cn,
            session.user.user_metadata?.full_name || session.user.user_metadata?.name || null,
            session.user.user_metadata?.workspace_slug || null,
          );
          // Their company already has a workspace. That is not a failure to log and
          // walk away from: without a screen they land in a blank app with no idea
          // what happened or who to ask.
          if (rpcErr?.domainInUse) {
            if (cancelled) return;
            setJoinBlocked(rpcErr);
            setRestoring(false);
            return;
          }
          if (rpcErr) console.error("workspace provisioning failed:", rpcErr.message || rpcErr);
          else sess = await loadCustomerSession(session.user.id, email);
        }
        if (cancelled || !sess) return;
        // Email-code two-factor: hold the workspace behind a one-time code when the
        // account uses it and this device is not trusted. sessionStorage marks a
        // pass so a refresh in the same tab does not re-prompt; a trusted device
        // (checked server-side via send-login-code) counts as a pass and skips the
        // email. Fails CLOSED: if the code service is unreachable we gate rather than
        // wave them through, since that is the whole point of a second factor.
        if (sess.profile?.email2fa) {
          let verified = false;
          try { verified = sessionStorage.getItem("aster.2fa.ok") === "1"; } catch { /* private mode */ }
          if (!verified) {
            const deviceToken = (typeof window !== "undefined" && localStorage.getItem("aster.2fa.device")) || "";
            let trusted = false;
            try {
              const { data: chk } = await supabase.functions.invoke("send-login-code", { body: { deviceToken, purpose: "login" } });
              trusted = !!chk?.trusted;
            } catch { trusted = false; }
            if (trusted) { try { sessionStorage.setItem("aster.2fa.ok", "1"); } catch { /* */ } }
            else {
              if (cancelled) return;
              setPending2fa(sess.profile.email || email || "");
              setRestoring(false);
              return;
            }
          }
        }
        // Multi-tenant: on the apex or a subdomain that isn't this workspace's,
        // forward to the correct <slug>.hireaster.com instead of loading here.
        if (needsWorkspaceRedirect(sess)) { setRedirecting(true); return; }
        setProfile(sess.profile);
        setCompany(sess.company);
        setCompanyLogoUrl(sess.logoUrl || null);
        setCompanyAddress(sess.address || "");
        setCompanyAddressParts(sess.addressParts || { ...EMPTY_ADDRESS });
        setCompanyRegNo(sess.registrationNo || "");
        if (sess.plan) setPlan(sess.plan);
        setPlanCycle(sess.planCycle || "monthly");
        setTrialDaysLeft(sess.trialDaysLeft || 0);
        setRenewsAt(sess.renewsAt || null);
        setSubStatus(sess.subStatus || null);
        setActivitiesSeenAt(sess.activitiesSeenAt || null);
        if (sess.calendarProvider) setProvider(sess.calendarProvider);
        if (sess.avatarPath) signedAvatarUrl(sess.avatarPath).then((u) => u && setAvatarUrl(u));
        if (sess.companyId) {
          setCompanyId(sess.companyId);
          setUserId(sess.userId);
          await hydrateWorkspace(sess.companyId, { seenAt: sess.activitiesSeenAt }); // finish before revealing the app
        }
        // Just redeemed an invite on this load: clear the token from state + URL
        // and drop them into the app, instead of leaving the accept form showing.
        if (joinedViaInvite && !cancelled) {
          setInvite(null);
          if (typeof window !== "undefined") window.history.replaceState({ aster: true }, "", "/");
          navigate(isInterviewer(sess.profile?.role) ? "interviews" : "dashboard");
        } else if (!cancelled && typeof window !== "undefined") {
          // Restored a session while sitting on the sign-in screen (a fresh login,
          // a cross-subdomain handoff, or the subdomain root that resolves to
          // login) — drop into the app rather than show a form to an authed user.
          const cur = screenFromPath(window.location.pathname);
          if (cur === "login" || cur === "signup") navigate(isInterviewer(sess.profile?.role) ? "interviews" : "dashboard");
        }
      } finally {
        if (!cancelled) setRestoring(false);
      }
    };

    // Listen instead of one-shot getSession: after an OAuth redirect the session
    // is parsed from the URL asynchronously, so getSession() can return null too
    // early and skip the domain gate. INITIAL_SESSION fires on load with the
    // stored session (or null); SIGNED_IN fires once the OAuth session lands.
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      // Defer out of the callback: calling supabase.auth methods (signOut) inside
      // the onAuthStateChange callback blocks on its internal lock and hangs, so
      // the domain-gate sign-out never completes. setTimeout(…,0) breaks the lock.
      if (event === "INITIAL_SESSION" || event === "SIGNED_IN") setTimeout(() => applySession(session), 0);
    });
    // If we arrived via a cross-subdomain handoff (#ws_at/#ws_rt), restore that
    // session now; setSession fires SIGNED_IN above, which runs applySession.
    consumeHandoffTokens();
    return () => { cancelled = true; subscription.unsubscribe(); };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // URL routing + phone/browser Back button: each navigate() pushes a matching
  // history entry with its path, so Back pops the in-app stack (never leaves
  // the site) and every screen has a dedicated, refreshable URL.
  useEffect(() => {
    const pathFor = (scr) => (scr === "apply" && typeof window !== "undefined" && applyJobFromPath(window.location.pathname) ? (window.location.pathname + window.location.search) : scr === "candidateProfile" && viewCandidateId ? (viewCandidateJobId ? `/candidates/${viewCandidateId}?job=${encodeURIComponent(viewCandidateJobId)}` : `/candidates/${viewCandidateId}`) : scr === "applicants" && activeJobId ? `/applicants/${activeJobId}` : scr === "product" ? ("/product" + (productSlug ? `/${productSlug}` : "")) : scr === "solutions" ? ("/solutions" + (solutionSlug ? `/${solutionSlug}` : "")) : scr === "blog" ? ("/blog" + (blogSlug ? `/${blogSlug}` : blogCat ? `/category/${blogCat}` : "")) : scr === "glossary" ? ("/resources/glossary" + (glossarySlug ? `/${glossarySlug}` : "")) : scr === "compare" ? ("/compare" + (compareSlug ? `/${compareSlug}` : "")) : scr === "trust" ? ("/trust" + (trustSlug ? `/${trustSlug}` : "")) : scr === "legal" ? (`/legal/${legalSlug || "privacy"}`) : (SCREEN_TO_PATH[scr] || "/"));
    if (typeof window !== "undefined") {
      // Seed browser history to match the initial (possibly deep-linked) stack.
      window.history.replaceState({ aster: true }, "", pathFor(history[0]));
      for (let i = 1; i < history.length; i++) {
        window.history.pushState({ aster: true }, "", pathFor(history[i]));
      }
    }
    // Follow the browser URL on Back/Forward and reconcile the in-app stack, so
    // the rendered screen never desyncs from the address bar. Popping blindly
    // broke this: after navigate("login") reset the stack, or after a landing
    // hash-anchor added browser entries the app didn't track, Back could leave
    // the login screen showing at the landing URL (and its menu links dead).
    const onPop = () => {
      const path = window.location.pathname;
      const cid = candidateIdFromPath(path);
      const pslug = productSlugFromPath(path);
      const sslug = solutionSlugFromPath(path);
      const binfo = blogInfoFromPath(path);
      const ginfo = glossaryInfoFromPath(path);
      const cinfo = compareInfoFromPath(path);
      const tinfo = trustInfoFromPath(path);
      const linfo = legalInfoFromPath(path);
      const ajob = applicantsJobFromPath(path);
      const target = cid ? "candidateProfile" : (ajob ? "applicants" : (pslug != null ? "product" : (sslug != null ? "solutions" : (binfo ? "blog" : (ginfo ? "glossary" : (cinfo ? "compare" : (tinfo ? "trust" : (linfo ? "legal" : (PATH_TO_SCREEN[path] || "landing")))))))));
      if (cid) { setViewCandidateId(cid); setViewCandidateJobId(new URLSearchParams(window.location.search).get("job")); }
      if (ajob) setActiveJobId(ajob);
      if (pslug != null) setProductSlug(pslug);
      if (sslug != null) setSolutionSlug(sslug);
      if (binfo) { setBlogSlug(binfo.kind === "post" ? binfo.slug : ""); setBlogCat(binfo.kind === "category" ? binfo.slug : ""); }
      if (ginfo) setGlossarySlug(ginfo.kind === "term" ? ginfo.slug : "");
      if (cinfo) setCompareSlug(cinfo.kind === "page" ? cinfo.slug : "");
      if (tinfo) setTrustSlug(tinfo.slug);
      if (linfo) setLegalSlug(linfo.slug);
      setHistory((h) => {
        const idx = h.lastIndexOf(target);
        if (idx >= 0) return h.slice(0, idx + 1);      // walk back to it in-stack
        if (AUTH_SCREENS.has(target) || target === "dashboard") return [target];
        return ["dashboard", target];                  // rebuild a sane stack
      });
    };
    window.addEventListener("popstate", onPop);
    return () => window.removeEventListener("popstate", onPop);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const viewCandidate = (candidateId, jobId = null, stage = null) => {
    setViewCandidateId(candidateId);
    setViewCandidateJobId(jobId);
    setViewCandidateStage(stage);
    // Keep the job in the URL so a refresh restores the pipeline context (the
    // scheduling / questions / scorecard panels all key off it).
    navigate("candidateProfile", jobId ? `/candidates/${candidateId}?job=${encodeURIComponent(jobId)}` : `/candidates/${candidateId}`);
  };

  // Open a Product marketing page (slug "" = overview).
  const goProduct = (slug = "") => {
    setProductSlug(slug);
    navigate("product", "/product" + (slug ? `/${slug}` : ""));
  };

  const goSolution = (slug = "") => {
    setSolutionSlug(slug);
    navigate("solutions", "/solutions" + (slug ? `/${slug}` : ""));
  };

  // Open a Resources page. goBlog({}) = index, {post} = article, {category} = filtered.
  const goBlog = (opts = {}) => {
    const post = opts.post || "";
    const cat = opts.category || "";
    setBlogSlug(post);
    setBlogCat(cat);
    navigate("blog", post ? `/blog/${post}` : cat ? `/blog/category/${cat}` : "/blog");
  };
  const goGlossary = (slug = "") => {
    setGlossarySlug(slug);
    navigate("glossary", slug ? `/resources/glossary/${slug}` : "/resources/glossary");
  };
  // Open a comparison page ("" = hub, a competitor slug, or "alternatives").
  const goCompare = (slug = "") => {
    setCompareSlug(slug);
    navigate("compare", slug ? `/compare/${slug}` : "/compare");
  };
  // Open the trust center ("" = hub, or compliance).
  const goTrust = (slug = "") => {
    setTrustSlug(slug);
    navigate("trust", slug ? `/trust/${slug}` : "/trust");
  };
  // Open a legal document (privacy | terms | dpa | cookies | aup | subprocessors).
  const goLegal = (slug = "privacy") => {
    setLegalSlug(slug);
    navigate("legal", `/legal/${slug}`);
  };
  const handlePreviewBooking = (request) => {
    setPreviewRequest(request);
    navigate("schedulePicker");
  };

  // Open the public application page for a job (what a candidate sees via the link).
  const handlePreviewApply = (job) => {
    setPreviewApplyJob(job);
    navigate("apply");
  };

  // Candidate confirmed a time on the public booking page.
  const confirmBooking = (candidateId, slot) => {
    setBookings((prev) => ({
      ...prev,
      [candidateId]: {
        ...(prev[candidateId] || {}),
        status: "scheduled",
        confirmedSlot: slot,
        // Lock in whichever provider was active when the interview was set up.
        provider: prev[candidateId]?.provider || defaultProvider,
      },
    }));
    // A confirmed interview moves the candidate into the Interviewing stage
    // (unless they're already further along, e.g. Offer/Hired).
    setStageOverrides((prev) => {
      const current = prev[candidateId];
      if (current === "offer" || current === "hired") return prev;
      if (canPersist) dbSetCandidateStage(companyId, candidateId, "interviewing");
      return { ...prev, [candidateId]: "interviewing" };
    });
  };

  // HR sent the invite (times proposed, awaiting candidate). On a live workspace,
  // persist the interview-invite row and email the candidate a link to /book/<token>.
  const markInviteSent = (candidateId, request) => {
    setBookings((prev) => ({
      ...prev,
      [candidateId]: { status: "sent", jobId: request.jobId || null, request, confirmedSlot: null, provider: defaultProvider },
    }));
    if (canPersist) {
      dbCreateInterviewInvite(companyId, {
        candidateId,
        jobId: request.jobId || null,
        interviewerName: request.interviewerName || null,
        interviewerEmail: request.interviewerEmail || null,
        proposedSlots: request.proposed_slots || [],
        provider: defaultProvider,
        attendees: request.attendees || [],
      }).then((token) => {
        if (token) supabase.functions.invoke("send-interview-invite", { body: { token } }).catch(() => {});
      });
    }
    // Scheduling this candidate resolves any open "request interview" so the
    // interviewer's lock clears and it stops counting as an outstanding request.
    const appId = (APPLICANTS_BY_JOB[request.jobId] || []).find((a) => a.candidateId === candidateId)?.applicationId;
    if (appId) {
      setScheduleRequests((prev) => prev.filter((r) => r.application_id !== appId));
      if (canPersist) supabase.from("schedule_requests").update({ resolved_at: new Date().toISOString() }).eq("application_id", appId).is("resolved_at", null).then(() => {}, () => {});
    }
  };

  // HR changed a candidate's pipeline stage. Persists it, and on a real move into
  // offer / hired / rejected also emails the candidate the matching Tier 2
  // template. `notify` is false for the "simulate the candidate's reply" preview,
  // which must never send a real email.
  const setCandidateStage = (candidateId, stage, { notify = true } = {}) => {
    const prevStage = stageOverrides[candidateId];
    setStageOverrides((prev) => ({ ...prev, [candidateId]: stage }));
    // Keep the loaded snapshot (baseStage) in sync so stage-derived statuses,
    // the job pipeline bar, the profile stage pill, the interviewer's interview
    // status, don't show a stale stage until the next reload.
    Object.values(APPLICANTS_BY_JOB).forEach((list) => list.forEach((a) => { if (a.candidateId === candidateId) a.baseStage = stage; }));
    // Stamp the hire date when a candidate is marked hired (drives "Hired {date}").
    if (stage === "hired") setHiredDates((prev) => (prev[candidateId] ? prev : { ...prev, [candidateId]: new Date().toISOString().slice(0, 10) }));
    if (!canPersist || prevStage === stage) return;
    dbSetCandidateStage(companyId, candidateId, stage);
    // 'offer' is intentionally excluded: offers are sent via the dedicated
    // sendOffer flow (which emails an accept/decline link), not here.
    if (notify && (stage === "hired" || stage === "rejected")) {
      supabase.functions
        .invoke("send-stage-email", { body: { candidate_id: candidateId, stage } })
        .catch(() => { /* best-effort: never block the stage change on email */ });
    }
  };

  // Delete a candidate for good. Applications and scorecards cascade via FK; a DB
  // trigger prunes any industry no other profile still has. Optimistically drop
  // them locally so lists update at once, then persist + resync from the DB.
  const deleteCandidate = (candidateId) => {
    MOCK_CANDIDATES = MOCK_CANDIDATES.filter((c) => c.id !== candidateId);
    setStageOverrides((prev) => { const { [candidateId]: _drop, ...rest } = prev; return rest; });
    navigate(-1);
    if (canPersist) dbDeleteCandidate(candidateId).then(() => { if (companyId) hydrateWorkspace(companyId); });
  };

  // Offer response loop: an offer is 'sent' to the candidate, who then 'accepted'
  const sendOffer = (candidateId, emailSent) => {
    setOffers((prev) => ({ ...prev, [candidateId]: { status: "sent", emailSent, sentAt: "just now" } }));
    // Move to Offer without the generic stage email; the offer email (with the
    // accept/decline link) is sent by send-offer below when HR chose to email.
    setCandidateStage(candidateId, "offer", { notify: false });
    if (canPersist && emailSent) {
      dbCreateOffer(companyId, { candidateId }).then((token) => {
        if (token) supabase.functions.invoke("send-offer", { body: { token } }).catch(() => {});
      });
    }
  };
  const respondOffer = (candidateId, accepted) => {
    // Accepting does NOT auto-hire: the candidate says yes, then HR reviews and
    // clicks "Mark as hired" to close the process (see the Decision panel).
    setOffers((prev) => ({ ...prev, [candidateId]: { ...(prev[candidateId] || {}), status: accepted ? "accepted" : "declined" } }));
    if (!accepted) setCandidateStage(candidateId, "declined", { notify: false });
  };

  const activeCandidate = MOCK_CANDIDATES.find((c) => c.id === viewCandidateId);

  // Candidates who have been hired are unavailable everywhere: excluded from AI
  // matching, badged & locked in lists, and blocked from re-applying. A hire is
  // global to the candidate (not per-job), derived from their effective stage.
  const hiredIds = new Set();
  Object.values(APPLICANTS_BY_JOB).flat().forEach((a) => {
    if ((stageOverrides[a.candidateId] ?? a.baseStage) === "hired") hiredIds.add(a.candidateId);
  });
  Object.entries(stageOverrides).forEach(([id, s]) => { if (s === "hired") hiredIds.add(id); });

  // The public "Ask Aster" assistant, mounted on every marketing surface. Its
  // CTAs reuse the same signup entry points as the hero/pricing buttons.
  const marketingChat = (
    <MarketingChat
      onStartTrial={() => { setSignupPlan("launch"); setSignupTrial(true); navigate("signup"); }}
      onContactSales={() => { setSignupPlan("enterprise"); setSignupTrial(false); navigate("signup"); }}
    />
  );

  // A returning signed-in user (session token already on disk) must never see a
  // flash of the marketing header while auth hydrates on refresh/hard-refresh or
  // when a route falls back to "/". Hold the Aster splash over every screen until
  // `restoring` clears. Public candidate links (apply / book / offer) are exempt
  // so a logged-in recruiter opening one still gets the candidate-facing page.
  if (((restoring && (bootHadSession || authTransitionPending)) || redirecting) && screen !== "apply" && screen !== "bookInterview" && screen !== "publicOffer") {
    return (
      <Shell>
        <AsterSplash />
      </Shell>
    );
  }

  // Screens that render standalone (no sidebar): the marketing site, login,
  // sign-up, and the public candidate booking page.
  if (screen === "landing") {
    return (
      <Shell>
        {marketingChat}
        <LandingScreen navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} logoUrl={logoUrl} setSignupPlan={setSignupPlan} setSignupCycle={setSignupCycle} setSignupTrial={setSignupTrial} />
      </Shell>
    );
  }

  if (screen === "product") {
    return (
      <Shell>
        {marketingChat}
        <ProductScreen slug={productSlug} navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "contactSales") {
    return (
      <Shell>
        {marketingChat}
        <ContactSalesScreen navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "solutions") {
    return (
      <Shell>
        {marketingChat}
        <SolutionsScreen slug={solutionSlug} navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "blog") {
    return (
      <Shell>
        {marketingChat}
        <BlogScreen slug={blogSlug} cat={blogCat} navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "glossary") {
    return (
      <Shell>
        {marketingChat}
        <GlossaryScreen slug={glossarySlug} navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "compare") {
    return (
      <Shell>
        {marketingChat}
        <CompareScreen slug={compareSlug} navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "trust") {
    return (
      <Shell>
        {marketingChat}
        <TrustScreen slug={trustSlug} navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} goTrust={goTrust} goLegal={goLegal} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "legal") {
    return (
      <Shell>
        {marketingChat}
        <LegalScreen slug={legalSlug} navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} goTrust={goTrust} goLegal={goLegal} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "gettingStarted") {
    return (
      <Shell>
        {marketingChat}
        <GettingStartedScreen navigate={navigate} goProduct={goProduct} goSolution={goSolution} goBlog={goBlog} goGlossary={goGlossary} goCompare={goCompare} goTrust={goTrust} goLegal={goLegal} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "login") {
    return (
      <Shell>
        <LoginScreen onAuthed={applyCustomerSession} navigate={navigate} logoUrl={logoUrl} ssoEnabled={platformFlags.sso_login} onJoinBlocked={setJoinBlocked} />
      </Shell>
    );
  }

  if (screen === "confirmEmail") {
    return (
      <Shell>
        <ConfirmEmailScreen navigate={navigate} />
      </Shell>
    );
  }

  if (screen === "forgotPassword") {
    return (
      <Shell>
        <ForgotPasswordScreen navigate={navigate} logoUrl={logoUrl} />
      </Shell>
    );
  }

  if (screen === "signup") {
    return (
      <Shell>
        <SignUpScreen
          navigate={navigate}
          logoUrl={logoUrl}
          onAuthed={applyCustomerSession}
          setCompany={setCompany}
          setProfile={setProfile}
          signupPlan={signupPlan}
          signupCycle={signupCycle}
          signupTrial={signupTrial}
          setPlan={setPlan}
          setPlanCycle={setPlanCycle}
          setTrialDaysLeft={setTrialDaysLeft}
          ssoEnabled={platformFlags.sso_login}
        />
      </Shell>
    );
  }

  if (screen === "acceptInvite") {
    return (
      <Shell>
        {invite
          ? <AcceptInviteScreen invite={invite} onAuthed={applyCustomerSession} navigate={navigate} logoUrl={logoUrl} />
          : <LoginScreen onAuthed={applyCustomerSession} navigate={navigate} logoUrl={logoUrl} ssoEnabled={platformFlags.sso_login} onJoinBlocked={setJoinBlocked} />}
      </Shell>
    );
  }

  if (screen === "schedulePicker") {
    return (
      <Shell>
        <div className="min-h-dvh" style={{ background: "var(--bg)" }}>
          <SchedulePickerScreen
            navigate={navigate}
            request={previewRequest}
            logoUrl={logoUrl}
            company={company}
            onConfirm={(slot) => previewRequest && confirmBooking(previewRequest.candidateId, slot)}
          />
        </div>
      </Shell>
    );
  }

  if (screen === "bookInterview") {
    const b = publicBooking;
    const centered = (node) => (
      <Shell><div className="min-h-dvh flex items-center justify-center px-6" style={{ background: "var(--bg)" }}>{node}</div></Shell>
    );
    if (!b || b.status === "loading") {
      return centered(<div className="w-8 h-8 rounded-full animate-spin" style={{ border: "2px solid var(--line-strong)", borderTopColor: "var(--brand)" }} />);
    }
    if (b.status === "notfound" || !b.data) {
      return centered(
        <div className="text-center max-w-sm">
          <h1 className="text-lg font-bold font-display mb-2" style={{ color: "var(--ink)" }}>Booking link not found</h1>
          <p className="text-sm" style={{ color: "var(--ink-2)" }}>This interview link isn't valid. It may be out of date, or the interview was already scheduled.</p>
        </div>
      );
    }
    return (
      <Shell>
        <BookInterviewScreen data={b.data} done={b.status === "done"} onConfirm={confirmPublicBooking} />
      </Shell>
    );
  }

  if (screen === "publicOffer") {
    const o = publicOffer;
    const centered = (node) => (
      <Shell><div className="min-h-dvh flex items-center justify-center px-6" style={{ background: "var(--bg)" }}>{node}</div></Shell>
    );
    if (!o || o.status === "loading") {
      return centered(<div className="w-8 h-8 rounded-full animate-spin" style={{ border: "2px solid var(--line-strong)", borderTopColor: "var(--brand)" }} />);
    }
    if (o.status === "notfound" || !o.data) {
      return centered(
        <div className="text-center max-w-sm">
          <h1 className="text-lg font-bold font-display mb-2" style={{ color: "var(--ink)" }}>Offer not found</h1>
          <p className="text-sm" style={{ color: "var(--ink-2)" }}>This offer link isn't valid. It may be out of date, or the offer was withdrawn.</p>
        </div>
      );
    }
    return (
      <Shell>
        <OfferScreen data={o.data} done={o.status === "done"} onRespond={respondPublicOffer} />
      </Shell>
    );
  }

  if (screen === "apply") {
    // Public visit via /apply/<id> (no in-app preview): render the standalone
    // apply page for the fetched job, with no admin chrome.
    if (!previewApplyJob) {
      const p = publicApply;
      const centered = (node) => (
        <Shell><div className="min-h-dvh flex items-center justify-center px-6" style={{ background: "var(--bg)" }}>{node}</div></Shell>
      );
      if (!p || p.status === "loading") {
        return centered(<div className="w-8 h-8 rounded-full animate-spin" style={{ border: "2px solid var(--line-strong)", borderTopColor: "var(--brand)" }} />);
      }
      if (p.status === "notfound" || !p.job) {
        return centered(
          <div className="text-center max-w-sm">
            <h1 className="text-lg font-bold font-display mb-2" style={{ color: "var(--ink)" }}>Job not found</h1>
            <p className="text-sm" style={{ color: "var(--ink-2)" }}>This job posting isn't available. The link may be out of date, or the role has been taken down.</p>
          </div>
        );
      }
      return (
        <Shell>
          <div className="min-h-dvh" style={{ background: "var(--bg)" }}>
            <ApplyScreen navigate={navigate} job={p.job} isPublic company={p.company} logoUrl={p.logoUrl || null} onApplied={() => {}} />
          </div>
        </Shell>
      );
    }

    // In-app admin preview: resolve the live job by id so its status is always
    // current (a job toggled closed after opening the preview reflects at once).
    const liveApplyJob = jobs.find((j) => j.id === previewApplyJob.id) || previewApplyJob;
    const _applyLimits = planLimits(plan);
    const applyPaused = false; // job posting is metered per cycle now, not by a concurrent cap that pauses roles
    const hiredEmails = new Set(MOCK_CANDIDATES.filter((c) => hiredIds.has(c.id) && c.parsed?.email).map((c) => c.parsed.email.toLowerCase()));
    return (
      <Shell>
        <div className="min-h-dvh" style={{ background: "var(--bg)" }}>
          <ApplyScreen navigate={navigate} job={liveApplyJob} paused={applyPaused} hiredEmails={hiredEmails} logoUrl={companyLogoUrl} company={company} onApplied={() => { if (companyId) hydrateWorkspace(companyId); }} />
        </div>
      </Shell>
    );
  }

  // Hold the authenticated app until the session + workspace have hydrated, so a
  // signed-in user never sees a flash of demo data before their real data loads.
  // Marketing / login / sign-up screens all returned above, so this only gates
  // the workspace.
  if (restoring) {
    return (
      <Shell>
        <AsterSplash />
      </Shell>
    );
  }

  // W4: signed-out visitors must not reach workspace-only screens. In live mode
  // (Supabase configured) `restoring` has finished above, so a null `userId`
  // here means no session — deep-linking to /dashboard etc. now lands on the
  // login screen instead of the app shell over demo data. Mock mode (no keys)
  // has no auth and no `userId`, so it is excluded to keep the preview working.
  if (hasSupabase && !userId && WORKSPACE_SCREENS.has(screen)) {
    return (
      <Shell>
        <LoginScreen onAuthed={applyCustomerSession} navigate={navigate} logoUrl={logoUrl} ssoEnabled={platformFlags.sso_login} onJoinBlocked={setJoinBlocked} />
      </Shell>
    );
  }

  if (joinBlocked) {
    return (
      <Shell>
        <JoinBlockedScreen
          info={joinBlocked}
          onSignOut={async () => { await supabase.auth.signOut(); window.location.assign("/login"); }}
        />
      </Shell>
    );
  }

  if (pending2fa) {
    return (
      <Shell>
        <LoginCodeGate
          email={pending2fa}
          onDone={() => { if (typeof window !== "undefined") window.location.reload(); }}
          onCancel={async () => { await supabase.auth.signOut(); if (typeof window !== "undefined") window.location.assign("/login"); }}
        />
      </Shell>
    );
  }

  if (deletedInfo) {
    return (
      <Shell>
        <DeletedWorkspaceScreen
          info={deletedInfo}
          logoUrl={logoUrl}
          onRestore={async () => {
            const { error } = await supabase.rpc("restore_workspace");
            if (error) return error.message || "Could not restore. The window may have passed.";
            if (typeof window !== "undefined") window.location.assign("/");
            return null;
          }}
          onSignOut={async () => { await supabase.auth.signOut(); if (typeof window !== "undefined") window.location.assign("/"); }}
        />
      </Shell>
    );
  }

  // Map each screen to the sidebar nav item that should appear active. For an
  // interviewer the only primary item is "Interviews", so their candidate views
  // and interviews all light it up.
  const activeNav = isInterviewer(profile?.role)
    ? "interviews"
    : screen === "candidateProfile" || screen === "candidates"
      ? "dashboard"
      : screen === "applicants"
        ? "jobs"
        : screen === "interviews"
          ? "interviewers"
          : screen;

  return (
    <Shell>
      {/* The first-run tour must key off the REAL screen and whether the workspace
          is genuinely new. activeNav aliases candidate profiles and the candidates
          list to "dashboard" to light the right rail icon, so keying the tour off
          active fired 'post your first job' over a populated candidate profile. And
          a workspace that already has jobs is not first-run: seeded, restored or
          multi-device, it should never see it. */}
      <SidebarLayout
        navigate={navigate}
        active={activeNav}
        onDashboard={screen === "dashboard"}
        isFreshWorkspace={jobs.length === 0}
        avatarUrl={avatarUrl}
        onSignOut={handleSignOut}
        logoUrl={logoUrl}
        profile={profile}
        unreadCount={activities.filter((a) => !a.read).length}
        activities={activities}
        onOpenNotifications={markActivitiesRead}
      >
        <ErrorBoundary key={screen}>
        {screen === "dashboard" && (
          <DashboardScreen
            navigate={navigate}
            jobs={jobs}
            candidates={MOCK_CANDIDATES}
            bookings={bookings}
            setCandidateFilter={setCandidateFilter}
            setJobStatusFilter={setJobStatusFilter}
            profile={profile}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
            range={dateRange}
            setRange={setDateRange}
            plan={effectivePlan}
            trialDaysLeft={trialActive ? trialDaysLeft : 0}
            onEndTrial={endTrial}
            hiredIds={hiredIds}
            avatarUrl={avatarUrl}
            parseUsage={parseUsage}
            applicantParseUsage={applicantParseUsage}
            matchRunsUsed={matchRunsUsed}
            aiInsightsUsed={aiInsightsUsed}
            company={company}
          />
        )}
        {screen === "profile" && (
          <ProfileScreen
            navigate={navigate}
            userId={userId}
            avatarUrl={avatarUrl}
            setAvatarUrl={setAvatarUrl}
            logoUrl={companyLogoUrl}
            setLogoUrl={setCompanyLogoUrl}
            whiteLabelOn={platformFlags.white_label}
            profile={profile}
            setProfile={setProfile}
            company={company}
            setCompany={setCompany}
            address={companyAddress}
            setAddress={setCompanyAddress}
            addressParts={companyAddressParts}
            setAddressParts={setCompanyAddressParts}
            regNo={companyRegNo}
            setRegNo={setCompanyRegNo}
            companyId={companyId}
            canPersist={canPersist}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
          />
        )}
        {screen === "settings" && (
          <SettingsScreen
            navigate={navigate}
            provider={defaultProvider}
            setProvider={setDefaultProvider}
            calendarConnected={calendarConnected}
            setCalendarConnected={setCalendarConnected}
            bookings={bookings}
            plan={effectivePlan}
            company={company}
            profile={profile}
            setProfile={setProfile}
            avatarUrl={avatarUrl}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
            companyId={companyId}
            canPersist={canPersist}
            logoUrl={logoUrl}
          />
        )}
        {/* Hiding the nav item is not a permission. Anyone can type /billing, so the
            route itself is gated too, and the edge functions reject a non-owner
            regardless of what the client does. */}
        {screen === "billing" && !isOwner(profile?.role) && (
          <RestrictedScreen
            navigate={navigate}
            title="Billing is for the account owner"
            body="Only the person who owns this workspace can see the plan, invoices and payment method. Ask them if you need a copy of an invoice."
          />
        )}
        {screen === "billing" && isOwner(profile?.role) && (
          <BillingScreen navigate={navigate} plan={plan} planCycle={planCycle} company={company} companyAddress={companyAddress} companyRegNo={companyRegNo} trialDaysLeft={trialActive ? trialDaysLeft : 0} renewsAt={renewsAt} subStatus={subStatus} onEndTrial={endTrial} profile={profile} avatarUrl={avatarUrl} activities={activities} onOpenNotifications={markActivitiesRead} />
        )}
        {screen === "upload" && <UploadScreen navigate={navigate} plan={effectivePlan} hiredIds={hiredIds} profile={profile} avatarUrl={avatarUrl} activities={activities} onOpenNotifications={markActivitiesRead} onImported={() => { if (companyId) hydrateWorkspace(companyId, { keepImportHistory: true }); }} parseUsage={parseUsage} importHistory={importHistory} onSaveRun={saveImportRun} />}
        {screen === "emailTemplates" && <EmailTemplatesScreen navigate={navigate} plan={effectivePlan} logoUrl={logoUrl} company={company} companyId={companyId} canPersist={canPersist} profile={profile} avatarUrl={avatarUrl} activities={activities} onOpenNotifications={markActivitiesRead} />}
        {screen === "jobs" && (
          <JobsScreen
            navigate={navigate}
            jobs={jobs}
            setJobs={setJobs}
            setActiveJobId={setActiveJobId}
            jobStatusFilter={jobStatusFilter}
            onPreviewApply={handlePreviewApply}
            plan={effectivePlan}
            keptJobId={keptJobId}
            profile={profile}
            avatarUrl={avatarUrl}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
            canPersist={canPersist}
            companyId={companyId}
            userId={userId}
            jobPostUsage={jobPostUsage}
            jobPostBlocked={jobPostBlocked}
            onConsumeJobPost={consumeJobPost}
            onDecideRequest={decideJobRequest}
            applicantParseUsage={applicantParseUsage}
          />
        )}
        {screen === "search" && (
          <SearchScreen navigate={navigate} candidates={MOCK_CANDIDATES} jobs={jobs} onViewCandidate={viewCandidate} onPreviewApply={handlePreviewApply} plan={effectivePlan} matchRunsUsed={matchRunsUsed} setMatchRunsUsed={setMatchRunsUsed} aiRankResetsAt={aiRankResetsAt} hiredIds={hiredIds} profile={profile} avatarUrl={avatarUrl} activities={activities} onOpenNotifications={markActivitiesRead} persist={searchStateRef} />
        )}
        {screen === "interviews" && (
          <InterviewsScreen
            navigate={navigate}
            bookings={bookings}
            candidates={MOCK_CANDIDATES}
            jobs={jobs}
            onViewCandidate={viewCandidate}
            role={profile?.role}
            profile={profile}
            jobAssignments={jobAssignments}
            currentUserId={userId}
            setActiveJobId={setActiveJobId}
            scorecards={scorecards}
            avatarUrl={avatarUrl}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
          />
        )}
        {screen === "openRoles" && (
          <OpenRolesScreen
            navigate={navigate}
            jobs={jobs}
            jobAssignments={jobAssignments}
            currentUserId={userId}
            profile={profile}
            avatarUrl={avatarUrl}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
            setActiveJobId={setActiveJobId}
            onRequestRole={() => setRequestRoleOpen(true)}
          />
        )}
        {screen === "interviewers" && (
          <InterviewersScreen navigate={navigate} interviewers={interviewers} setInterviewers={setInterviewers} pendingInvites={pendingInvites} setPendingInvites={setPendingInvites} reloadTeam={reloadTeam} defaultProvider={defaultProvider} bookings={bookings} calendarConnected={calendarConnected} plan={effectivePlan} profile={profile} avatarUrl={avatarUrl} activities={activities} onOpenNotifications={markActivitiesRead} />
        )}
        {screen === "candidateProfile" && !activeCandidate && (
          // The candidate isn't in the workspace (just deleted, or a stale deep
          // link). Show a graceful notice instead of crashing on undefined.
          <div className="px-4 sm:px-6 py-8 sm:py-10">
            <div className="max-w-2xl mx-auto">
              <BackLink onClick={() => navigate("dashboard")}>← Dashboard</BackLink>
              <p className="text-sm mt-4" style={{ color: "var(--ink-3)" }}>This candidate is no longer in your workspace.</p>
            </div>
          </div>
        )}
        {screen === "candidateProfile" && activeCandidate && (
          <CandidateProfileScreen
            navigate={navigate}
            candidate={activeCandidate}
            jobs={jobs}
            interviewers={interviewers}
            onPreviewBooking={handlePreviewBooking}
            contextJobId={viewCandidateJobId}
            initialStage={viewCandidateStage}
            booking={activeCandidate ? bookings[activeCandidate.id] : null}
            allBookings={bookings}
            onInviteSent={markInviteSent}
            provider={defaultProvider}
            calendarConnected={calendarConnected}
            plan={effectivePlan}
            scorecards={activeCandidate ? (scorecards[activeCandidate.id] || []) : []}
            onSubmitScorecard={(card) => activeCandidate && addScorecard(activeCandidate.id, card, viewCandidateJobId)}
            onSetAttendance={(ids) => activeCandidate && setAttendance(activeCandidate.id, ids)}
            onSubstitute={(oldId, replacement) => activeCandidate && substituteAttendee(activeCandidate.id, oldId, replacement, viewCandidateJobId)}
            stage={activeCandidate ? (stageOverrides[activeCandidate.id] ?? viewCandidateStage ?? null) : null}
            onSetStage={(s, opts) => activeCandidate && setCandidateStage(activeCandidate.id, s, opts)}
            onDelete={() => activeCandidate && deleteCandidate(activeCandidate.id)}
            offer={activeCandidate ? offers[activeCandidate.id] : null}
            onSendOffer={(emailSent) => activeCandidate && sendOffer(activeCandidate.id, emailSent)}
            onRespondOffer={(accepted) => activeCandidate && respondOffer(activeCandidate.id, accepted)}
            hiredIds={hiredIds}
            profile={profile}
            currentUserId={userId}
            scheduleRequests={scheduleRequests}
            onRequestScheduling={requestScheduling}
            savedQuestions={activeCandidate && viewCandidateJobId ? (interviewQuestions[`${activeCandidate.id}:${viewCandidateJobId}`] || null) : null}
            onGenerateQuestions={(qs) => activeCandidate && viewCandidateJobId && generateInterviewQuestions(activeCandidate.id, viewCandidateJobId, qs)}
            avatarUrl={avatarUrl}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
            jobAssignments={jobAssignments}
            aiInsightsUsed={aiInsightsUsed}
            setAiInsightsUsed={setAiInsightsUsed}
            insightsCache={insightsCache}
            setInsightsCache={setInsightsCache}
          />
        )}
        {screen === "candidates" && (
          <CandidateListScreen
            navigate={navigate}
            candidates={MOCK_CANDIDATES}
            jobs={jobs}
            filter={candidateFilter}
            onViewCandidate={viewCandidate}
            plan={effectivePlan}
            hiredIds={hiredIds}
            hiredDates={hiredDates}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
            avatarUrl={avatarUrl}
            profile={profile}
          />
        )}
        {screen === "applicants" && (
          <ApplicantsScreen
            key={activeJobId}
            navigate={navigate}
            companyId={companyId}
            jobs={jobs}
            activeJobId={activeJobId}
            onViewCandidate={viewCandidate}
            stageOverrides={stageOverrides}
            onStageChange={setCandidateStage}
            plan={effectivePlan}
            matchRunsUsed={matchRunsUsed}
            setMatchRunsUsed={setMatchRunsUsed}
            aiRankResetsAt={aiRankResetsAt}
            bookings={bookings}
            hiredIds={hiredIds}
            profile={profile}
            avatarUrl={avatarUrl}
            activities={activities}
            onOpenNotifications={markActivitiesRead}
            interviewers={interviewers}
            jobAssignments={jobAssignments}
            onAssignInterviewer={assignInterviewer}
            onUnassignInterviewer={unassignInterviewer}
            onCloseJob={(jobId) => { setJobs((prev) => prev.map((j) => (j.id === jobId ? { ...j, status: "closed" } : j))); if (canPersist) dbSetJobStatus(jobId, "closed"); }}
            reloadTeam={reloadTeam}
            shortlistedApps={shortlistedApps}
            onToggleShortlist={toggleShortlist}
          />
        )}
        </ErrorBoundary>
      </SidebarLayout>
      <NewJobModal open={newJobOpen} onClose={() => setNewJobOpen(false)} jobs={jobs} setJobs={setJobs} plan={effectivePlan} navigate={navigate} onCreate={canPersist ? (p) => dbCreateJob(companyId, userId, p) : null} onUpdate={canPersist ? (id, p) => dbUpdateJob(id, p) : null} jobPostBlocked={jobPostBlocked} jobPostUsage={jobPostUsage} onConsumeJobPost={consumeJobPost} />
      <NewJobModal open={requestRoleOpen} onClose={() => setRequestRoleOpen(false)} jobs={jobs} setJobs={setJobs} plan={effectivePlan} navigate={navigate} onCreate={canPersist ? (p) => dbRequestJob(p) : null} requestMode requesterId={userId} requesterName={`${profile?.firstName || ""} ${profile?.lastName || ""}`.trim()} />
    </Shell>
  );
}
